import { Medicine, Sale, INITIAL_MEDICINES } from '../constants';
import { Medicine as MedicineType, Sale as SaleType } from '../types';

const MEDICINES_KEY = 'pharma_core_medicines';
const SALES_KEY = 'pharma_core_sales';

class StorageService {
  getMedicines(): MedicineType[] {
    const stored = localStorage.getItem(MEDICINES_KEY);
    if (!stored) {
      // @ts-ignore - casting readonly to mutable for initial setup
      const initial: MedicineType[] = [...INITIAL_MEDICINES];
      localStorage.setItem(MEDICINES_KEY, JSON.stringify(initial));
      return initial;
    }
    return JSON.parse(stored);
  }

  saveMedicines(medicines: MedicineType[]) {
    localStorage.setItem(MEDICINES_KEY, JSON.stringify(medicines));
  }

  getSales(): SaleType[] {
    const stored = localStorage.getItem(SALES_KEY);
    return stored ? JSON.parse(stored) : [];
  }

  addSale(sale: SaleType) {
    const sales = this.getSales();
    sales.push(sale);
    localStorage.setItem(SALES_KEY, JSON.stringify(sales));

    // Update inventory
    const medicines = this.getMedicines();
    sale.items.forEach(item => {
      const medIndex = medicines.findIndex(m => m.id === item.id);
      if (medIndex >= 0) {
        medicines[medIndex].stock -= item.quantity;
      }
    });
    this.saveMedicines(medicines);
  }

  resetData() {
    localStorage.removeItem(MEDICINES_KEY);
    localStorage.removeItem(SALES_KEY);
    window.location.reload();
  }
}

export const storageService = new StorageService();

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || ''; // Ideally from env

export const getDrugInfo = async (drugName: string, queryType: 'interactions' | 'side_effects' | 'general'): Promise<string> => {
  if (!apiKey) return "API Key missing. Please configure.";

  try {
    const ai = new GoogleGenAI({ apiKey });
    const model = 'gemini-3-flash-preview';

    let prompt = "";
    switch(queryType) {
      case 'interactions':
        prompt = `What are the common drug interactions for ${drugName}? Keep it concise and bulleted.`;
        break;
      case 'side_effects':
        prompt = `What are the common side effects of ${drugName}? Keep it concise.`;
        break;
      case 'general':
        prompt = `Provide a brief medical summary for ${drugName} (uses, dosage forms).`;
        break;
    }

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });

    return response.text || "No information available.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error fetching AI response.";
  }
};

import React from 'react';
import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  className, 
  variant = 'primary', 
  size = 'md', 
  children, 
  ...props 
}) => {
  const baseStyles = "rounded-lg font-medium transition-all duration-200 active:scale-95 flex items-center justify-center gap-2";

  const variants = {
    primary: "bg-medical-blue text-white hover:bg-blue-600 shadow-md shadow-blue-500/20",
    secondary: "bg-white text-medical-dark border border-gray-200 hover:bg-gray-50",
    danger: "bg-medical-red text-white hover:bg-red-600 shadow-md shadow-red-500/20",
    ghost: "bg-transparent text-gray-600 hover:bg-gray-100"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base"
  };

  return (
    <button 
      className={twMerge(clsx(baseStyles, variants[variant], sizes[size], className))}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Lock } from 'lucide-react';
import { Button } from './ui/Button';

interface PinModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  requiredPin: string;
  title?: string;
}

export const PinModal: React.FC<PinModalProps> = ({ isOpen, onClose, onSuccess, requiredPin, title = "Security Check" }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  useEffect(() => {
    if (isOpen) {
      setPin('');
      setError(false);
    }
  }, [isOpen]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === requiredPin) {
      onSuccess();
      onClose();
    } else {
      setError(true);
      setPin('');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl p-6 w-full max-w-sm border border-white/40 animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-2 text-medical-blue">
            <Lock className="w-5 h-5" />
            <h3 className="font-semibold text-lg">{title}</h3>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="relative">
            <input
              type="password"
              value={pin}
              onChange={(e) => {
                setPin(e.target.value);
                setError(false);
              }}
              placeholder="Enter Master PIN"
              className="w-full text-center text-2xl tracking-[0.5em] font-bold py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-medical-blue focus:border-transparent bg-gray-50"
              autoFocus
              maxLength={7}
            />
          </div>

          {error && (
            <p className="text-red-500 text-xs text-center font-medium">Incorrect PIN. Access Denied.</p>
          )}

          <div className="flex gap-3 mt-4">
             <Button type="button" variant="secondary" onClick={onClose} className="flex-1">Cancel</Button>
             <Button type="submit" className="flex-1">Verify</Button>
          </div>
        </form>
      </div>
    </div>
  );
};

