import React from 'react';
import { Medicine } from '../types';
import { clsx } from 'clsx';
import { AlertTriangle, Pill } from 'lucide-react';
import { LOW_STOCK_THRESHOLD, EXPIRY_WARNING_DAYS } from '../constants';

interface MedicineCardProps {
  medicine: Medicine;
  onClick: (medicine: Medicine) => void;
}

export const MedicineCard: React.FC<MedicineCardProps> = ({ medicine, onClick }) => {
  const isLowStock = medicine.stock <= LOW_STOCK_THRESHOLD;
  const isOutOfStock = medicine.stock === 0;

  const expiryDate = new Date(medicine.expiryDate);
  const today = new Date();
  const diffTime = expiryDate.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  const isExpiringSoon = diffDays <= EXPIRY_WARNING_DAYS && diffDays > 0;
  const isExpired = diffDays <= 0;

  return (
    <div 
      onClick={() => !isOutOfStock && onClick(medicine)}
      className={clsx(
        "relative flex flex-col p-4 rounded-xl border transition-all duration-200 cursor-pointer glass-card select-none hover:shadow-lg hover:-translate-y-1",
        isOutOfStock 
          ? "opacity-60 grayscale cursor-not-allowed border-gray-200" 
          : isLowStock 
            ? "border-red-200 bg-red-50/10" 
            : "border-gray-100 bg-white"
      )}
    >
      {/* Badges */}
      <div className="absolute top-2 right-2 flex flex-col gap-1 items-end">
        {isExpiringSoon && !isExpired && (
           <span className="bg-orange-100 text-orange-700 text-[10px] font-bold px-2 py-0.5 rounded-full border border-orange-200">
             Exp: {diffDays}d
           </span>
        )}
        {isExpired && (
           <span className="bg-red-100 text-red-700 text-[10px] font-bold px-2 py-0.5 rounded-full border border-red-200">
             EXPIRED
           </span>
        )}
      </div>

      <div className="mb-3">
        <div className={clsx("w-10 h-10 rounded-full flex items-center justify-center mb-2", isLowStock ? "bg-red-100 text-red-600" : "bg-blue-50 text-medical-blue")}>
          <Pill size={20} />
        </div>
        <h3 className="font-bold text-gray-800 leading-tight">{medicine.name}</h3>
        <p className="text-xs text-gray-500 font-medium mt-1 uppercase tracking-wide truncate" title={medicine.genericName}>
          {medicine.genericName}
        </p>
      </div>

      <div className="mt-auto flex items-end justify-between">
        <div>
           <p className="text-xs text-gray-400 mb-0.5">{medicine.unit}</p>
           <p className="text-lg font-bold text-medical-blue">${medicine.price.toFixed(2)}</p>
        </div>
        <div className={clsx("text-xs font-semibold px-2 py-1 rounded-md", 
            isOutOfStock ? "bg-gray-200 text-gray-600" : 
            isLowStock ? "bg-red-100 text-red-700" : "bg-green-100 text-medical-green"
        )}>
           {isOutOfStock ? '0 LEFT' : `${medicine.stock} LEFT`}
        </div>
      </div>

      {/* Low Stock Border Indicator */}
      {isLowStock && !isOutOfStock && (
        <div className="absolute inset-0 border-2 border-red-400 rounded-xl pointer-events-none opacity-20"></div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, Plus, Minus, CreditCard, Banknote, FileText } from 'lucide-react';
import { Medicine, CartItem, Sale } from '../types';
import { MedicineCard } from '../components/MedicineCard';
import { Button } from '../components/ui/Button';
import { storageService } from '../services/storageService';
import { clsx } from 'clsx';
import { v4 as uuidv4 } from 'uuid'; // Just use random string gen if uuid not avail, but we'll simulate

const Counter: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'Card' | 'UPI'>('Cash');

  useEffect(() => {
    // Load fresh stock every time counter mounts to ensure sync
    setMedicines(storageService.getMedicines());
  }, []);

  const filteredMedicines = useMemo(() => {
    const term = search.toLowerCase();
    return medicines.filter(m => 
      m.name.toLowerCase().includes(term) || 
      m.genericName.toLowerCase().includes(term) ||
      m.category.toLowerCase().includes(term)
    );
  }, [medicines, search]);

  const addToCart = (medicine: Medicine) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === medicine.id);
      if (existing) {
        if (existing.quantity >= medicine.stock) return prev; // Cannot add more than stock
        return prev.map(item => item.id === medicine.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...medicine, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => {
      return prev.map(item => {
        if (item.id === id) {
          const newQty = item.quantity + delta;
          if (newQty <= 0) return item;
          // Check stock limit
          const med = medicines.find(m => m.id === id);
          if (med && newQty > med.stock) return item;
          return { ...item, quantity: newQty };
        }
        return item;
      });
    });
  };

  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const tax = subtotal * 0.0; // Assuming tax included or 0 for now
  const total = subtotal + tax;

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const sale: Sale = {
      id: Math.random().toString(36).substr(2, 9),
      date: new Date().toISOString(),
      items: cart,
      total: total,
      staffName: 'Current User', // Replace with actual context user
      paymentMethod
    };

    storageService.addSale(sale);

    // Update local state to reflect stock changes immediately without reload
    const updatedMedicines = medicines.map(m => {
      const cartItem = cart.find(c => c.id === m.id);
      if (cartItem) {
        return { ...m, stock: m.stock - cartItem.quantity };
      }
      return m;
    });
    setMedicines(updatedMedicines);

    setCart([]);
    alert('Sale Completed Successfully! \nReceipt sent to WhatsApp (Simulated)');
  };

  return (
    <div className="flex h-full gap-6">
      {/* Left: Medicine Grid */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {/* Search Bar */}
        <div className="mb-6 relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Search by Brand Name or Generic Salt..." 
            className="w-full pl-12 pr-4 py-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-medical-blue focus:border-transparent outline-none shadow-sm text-lg"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            autoFocus
          />
        </div>

        {/* Grid */}
        <div className="flex-1 overflow-y-auto pr-2 pb-20">
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
            {filteredMedicines.map(med => (
              <MedicineCard key={med.id} medicine={med} onClick={addToCart} />
            ))}
          </div>
          {filteredMedicines.length === 0 && (
             <div className="flex flex-col items-center justify-center h-64 text-gray-400">
               <p>No medicines found.</p>
             </div>
          )}
        </div>
      </div>

      {/* Right: Cart/Sidebar */}
      <div className="w-96 glass-panel rounded-2xl flex flex-col border border-gray-200 shadow-xl">
        <div className="p-5 border-b border-gray-100 bg-white/50 rounded-t-2xl">
          <div className="flex items-center justify-between">
            <h2 className="font-bold text-gray-800 flex items-center gap-2">
              <ShoppingCart className="text-medical-blue" /> Current Sale
            </h2>
            <span className="bg-blue-100 text-blue-700 text-xs font-bold px-2 py-1 rounded-lg">
              {cart.length} Items
            </span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
              <ShoppingCart size={48} className="mb-3" />
              <p>Cart is empty</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between group">
                <div className="flex-1">
                  <h4 className="font-semibold text-gray-800 text-sm">{item.name}</h4>
                  <p className="text-xs text-gray-500">{item.genericName}</p>
                  <p className="text-sm font-bold text-medical-blue mt-1">${(item.price * item.quantity).toFixed(2)}</p>
                </div>

                <div className="flex items-center gap-3">
                   <div className="flex items-center bg-gray-50 rounded-lg p-1 border border-gray-200">
                      <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-gray-200 rounded-md transition-colors"><Minus size={14} /></button>
                      <span className="w-8 text-center font-medium text-sm">{item.quantity}</span>
                      <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-gray-200 rounded-md transition-colors"><Plus size={14} /></button>
                   </div>
                   <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-red-500 transition-colors">
                     <Trash2 size={18} />
                   </button>
                </div>
              </div>
            ))
          )}
        </div>

        <div className="p-5 bg-white border-t border-gray-200 rounded-b-2xl">
          <div className="space-y-2 mb-4">
            <div className="flex justify-between text-sm text-gray-600">
              <span>Subtotal</span>
              <span>${subtotal.toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-lg font-bold text-gray-800">
              <span>Total</span>
              <span>${total.toFixed(2)}</span>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2 mb-4">
            {['Cash', 'Card', 'UPI'].map((method) => (
              <button
                key={method}
                onClick={() => setPaymentMethod(method as any)}
                className={clsx(
                  "py-2 rounded-lg text-xs font-semibold border transition-all flex flex-col items-center gap-1",
                  paymentMethod === method 
                    ? "bg-medical-blue text-white border-medical-blue" 
                    : "bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100"
                )}
              >
                {method === 'Cash' && <Banknote size={14} />}
                {method === 'Card' && <CreditCard size={14} />}
                {method === 'UPI' && <FileText size={14} />}
                {method}
              </button>
            ))}
          </div>

          <Button 
            className="w-full py-3 text-lg shadow-lg shadow-blue-500/30" 
            onClick={handleCheckout}
            disabled={cart.length === 0}
          >
            Checkout
          </Button>
        </div>
      </div>
    </div>
  );
};

export default Counter;

import React, { useState, useEffect } from 'react';
import { Plus, Search, AlertTriangle, Edit, Trash } from 'lucide-react';
import { Medicine } from '../types';
import { storageService } from '../services/storageService';
import { Button } from '../components/ui/Button';
import { PinModal } from '../components/PinModal';
import { MASTER_PIN, LOW_STOCK_THRESHOLD } from '../constants';
import { clsx } from 'clsx';

const Inventory: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [isPinModalOpen, setPinModalOpen] = useState(false);
  const [pendingAction, setPendingAction] = useState<(() => void) | null>(null);

  useEffect(() => {
    setMedicines(storageService.getMedicines());
  }, []);

  const filtered = medicines.filter(m => 
    m.name.toLowerCase().includes(search.toLowerCase()) ||
    m.genericName.toLowerCase().includes(search.toLowerCase())
  );

  const handleDelete = (id: string) => {
