        <div className="p-4 border-t border-gray-100 bg-gray-50 flex gap-3 print:hidden">
          <Button variant="secondary" onClick={onClose} className="flex-1">Close</Button>
          <Button onClick={handlePrint} className="flex-1 gap-2">
            <Printer size={18} /> Print Invoice
          </Button>
        </div>
      </div>

      {/* Print Specific Styles */}
      <style>{`
        @media print {
          body * {
            visibility: hidden;
          }
          .fixed, .fixed * {
            visibility: visible;
          }
          .fixed {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
            height: 100%;
            background: white;
            padding: 20px;
          }
          .print\\:hidden {
            display: none !important;
          }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, Plus, Minus, CreditCard, Banknote, FileText, Filter, Printer } from 'lucide-react';
import { Medicine, CartItem, Sale } from '../types';
import { MedicineCard } from '../components/MedicineCard';
import { Button } from '../components/ui/Button';
import { InvoiceModal } from '../components/InvoiceModal';
import { storageService } from '../services/storageService';
import { CURRENCY, CATEGORIES, UNITS } from '../constants';
import { clsx } from 'clsx';

const Counter: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedUnit, setSelectedUnit] = useState('All');

  const [cart, setCart] = useState<CartItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'Card' | 'UPI'>('Cash');
  const [lastSale, setLastSale] = useState<Sale | null>(null);
  const [showInvoice, setShowInvoice] = useState(false);

  useEffect(() => {
    setMedicines(storageService.getMedicines());
  }, []);

  const filteredMedicines = useMemo(() => {
    const term = search.toLowerCase();
    const today = new Date();
    today.setHours(0,0,0,0);

    return medicines.filter(m => {
      // 1. Expiry Check
      const expiry = new Date(m.expiryDate);
      if (expiry < today) return false; // Hide expired items

      // 2. Search
      const matchesSearch = 
        m.name.toLowerCase().includes(term) || 
        m.genericName.toLowerCase().includes(term);

      // 3. Filters
      const matchesCategory = selectedCategory === 'All' || m.category === selectedCategory;
      const matchesUnit = selectedUnit === 'All' || m.unit === selectedUnit;

      return matchesSearch && matchesCategory && matchesUnit;
    });
  }, [medicines, search, selectedCategory, selectedUnit]);

  const addToCart = (medicine: Medicine) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === medicine.id);
      if (existing) {
        if (existing.quantity >= medicine.stock) return prev; 
        return prev.map(item => item.id === medicine.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...medicine, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => {
      return prev.map(item => {
        if (item.id === id) {
          const newQty = item.quantity + delta;
          if (newQty <= 0) return item;
          const med = medicines.find(m => m.id === id);
          if (med && newQty > med.stock) return item;
          return { ...item, quantity: newQty };
        }
        return item;
      });
    });
  };

  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const total = subtotal; // Tax can be added here

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const sale: Sale = {
      id: Math.floor(Math.random() * 900000 + 100000).toString(), // 6 digit ID
      date: new Date().toISOString(),
      items: cart,
      total: total,
      staffName: 'Staff', // Using default
      paymentMethod
    };

    storageService.addSale(sale);

    // Update local state
    const updatedMedicines = medicines.map(m => {
      const cartItem = cart.find(c => c.id === m.id);
      if (cartItem) {
        return { ...m, stock: m.stock - cartItem.quantity };
      }
      return m;
    });
    setMedicines(updatedMedicines);
    setCart([]);

    // Show Invoice
    setLastSale(sale);
    setShowInvoice(true);
  };

  return (
    <>
      <div className="flex h-full gap-6">
        {/* Left: Medicine Grid */}
        <div className="flex-1 flex flex-col h-full overflow-hidden">
          {/* Controls */}
          <div className="mb-6 flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input 
                type="text" 
                placeholder="Search Brand or Salt..." 
                className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-medical-blue focus:border-transparent outline-none shadow-sm text-base"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                autoFocus
              />
            </div>

            <div className="flex gap-2">
               <select 
                 className="px-4 py-3 rounded-xl border border-gray-200 bg-white text-gray-700 text-sm focus:ring-2 focus:ring-medical-blue outline-none cursor-pointer"
                 value={selectedCategory}
                 onChange={(e) => setSelectedCategory(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
               </select>

               <select 
                 className="px-4 py-3 rounded-xl border border-gray-200 bg-white text-gray-700 text-sm focus:ring-2 focus:ring-medical-blue outline-none cursor-pointer"
                 value={selectedUnit}
                 onChange={(e) => setSelectedUnit(e.target.value)}
               >
                 <option value="All">All Units</option>
                 {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
               </select>
            </div>
          </div>

          {/* Grid */}
          <div className="flex-1 overflow-y-auto pr-2 pb-20">
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
              {filteredMedicines.map(med => (
                <MedicineCard key={med.id} medicine={med} onClick={addToCart} />
              ))}
            </div>
            {filteredMedicines.length === 0 && (
               <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                 <p>No medicines found.</p>
                 <p className="text-xs mt-2 opacity-70">(Expired items are hidden)</p>
               </div>
            )}
          </div>
        </div>

        {/* Right: Cart */}
        <div className="w-96 glass-panel rounded-2xl flex flex-col border border-gray-200 shadow-xl">
          <div className="p-5 border-b border-gray-100 bg-white/50 rounded-t-2xl">
            <div className="flex items-center justify-between">
              <h2 className="font-bold text-gray-800 flex items-center gap-2">
                <ShoppingCart className="text-medical-blue" /> Current Sale
              </h2>
              <span className="bg-blue-100 text-blue-700 text-xs font-bold px-2 py-1 rounded-lg">
                {cart.length} Items
              </span>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                <ShoppingCart size={48} className="mb-3" />
                <p>Cart is empty</p>
              </div>
            ) : (
              cart.map(item => (
                <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between group">
                  <div className="flex-1">
                    <h4 className="font-semibold text-gray-800 text-sm">{item.name}</h4>
                    <p className="text-[10px] text-gray-500">{item.genericName}</p>
                    <p className="text-sm font-bold text-medical-blue mt-1">{CURRENCY}{(item.price * item.quantity).toFixed(2)}</p>
                  </div>

                  <div className="flex items-center gap-3">
                     <div className="flex items-center bg-gray-50 rounded-lg p-1 border border-gray-200">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-gray-200 rounded-md transition-colors"><Minus size={14} /></button>
                        <span className="w-8 text-center font-medium text-sm">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-gray-200 rounded-md transition-colors"><Plus size={14} /></button>
                     </div>
                     <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-red-500 transition-colors">
                       <Trash2 size={18} />
                     </button>
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="p-5 bg-white border-t border-gray-200 rounded-b-2xl">
            <div className="space-y-2 mb-4">
              <div className="flex justify-between text-lg font-bold text-gray-800">
                <span>Total</span>
                <span>{CURRENCY}{total.toFixed(2)}</span>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2 mb-4">
              {['Cash', 'Card', 'UPI'].map((method) => (
                <button
                  key={method}
                  onClick={() => setPaymentMethod(method as any)}
                  className={clsx(
                    "py-2 rounded-lg text-xs font-semibold border transition-all flex flex-col items-center gap-1",
                    paymentMethod === method 
                      ? "bg-medical-blue text-white border-medical-blue" 
                      : "bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100"
                  )}
                >
                  {method === 'Cash' && <Banknote size={14} />}
                  {method === 'Card' && <CreditCard size={14} />}
                  {method === 'UPI' && <FileText size={14} />}
                  {method}
                </button>
              ))}
            </div>

            <Button 
              className="w-full py-3 text-lg shadow-lg shadow-blue-500/30" 
              onClick={handleCheckout}
              disabled={cart.length === 0}
            >
              Checkout & Print
            </Button>
          </div>
        </div>
      </div>

      <InvoiceModal 
        sale={lastSale} 
        onClose={() => setShowInvoice(false)} 
      />
      {showInvoice && <div className="fixed inset-0 z-40 bg-black/20" onClick={() => setShowInvoice(false)}/>}
    </>
  );
};

export default Counter;

import React, { useState, useEffect } from 'react';
import { Truck, ArrowUpRight, ArrowDownLeft, Calendar } from 'lucide-react';
import { Medicine, StockEntry } from '../types';
import { storageService } from '../services/storageService';
import { Button } from '../components/ui/Button';
import { CURRENCY } from '../constants';
import { clsx } from 'clsx';

const Stock: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [entries, setEntries] = useState<StockEntry[]>([]);

  // Form State
  const [selectedMedId, setSelectedMedId] = useState('');
  const [quantity, setQuantity] = useState(0);
  const [type, setType] = useState<'IN' | 'OUT'>('IN');
  const [reason, setReason] = useState('New Batch');
  const [batch, setBatch] = useState('');

  useEffect(() => {
    setMedicines(storageService.getMedicines());
    setEntries(storageService.getStockEntries().reverse()); // Newest first
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedMedId || quantity <= 0) return;

    const med = medicines.find(m => m.id === selectedMedId);
    if (!med) return;

    const entry: StockEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      medicineId: med.id,
      medicineName: med.name,
      quantity,
      type,
      reason,
      batchNumber: type === 'IN' ? batch : undefined
    };

    storageService.addStockEntry(entry);

    // Refresh
    setMedicines(storageService.getMedicines());
    setEntries(storageService.getStockEntries().reverse());

    // Reset Form
    setQuantity(0);
    setBatch('');
  };

  return (
    <div className="h-full flex gap-6">
       {/* Left: Entry Form */}
       <div className="w-80 flex flex-col gap-4">
         <div className="glass-panel p-6 rounded-xl border border-gray-200">
           <div className="flex items-center gap-2 mb-4 text-medical-blue">
             <Truck size={24} />
             <h2 className="text-lg font-bold">Stock Management</h2>
           </div>

           <form onSubmit={handleSubmit} className="space-y-4">
             <div>
               <label className="text-xs font-semibold text-gray-500 uppercase">Action Type</label>
               <div className="flex gap-2 mt-1">
                 <button type="button" onClick={() => { setType('IN'); setReason('New Batch'); }} className={clsx("flex-1 py-2 rounded-lg text-sm font-medium border transition-colors", type === 'IN' ? "bg-green-50 border-green-200 text-green-700" : "bg-gray-50 border-gray-200 text-gray-500")}>Stock In</button>
                 <button type="button" onClick={() => { setType('OUT'); setReason('Expired'); }} className={clsx("flex-1 py-2 rounded-lg text-sm font-medium border transition-colors", type === 'OUT' ? "bg-red-50 border-red-200 text-red-700" : "bg-gray-50 border-gray-200 text-gray-500")}>Stock Out</button>
               </div>
             </div>

             <div>
               <label className="text-xs font-semibold text-gray-500 uppercase">Select Medicine</label>
               <select 
                 className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                 value={selectedMedId}
                 onChange={(e) => setSelectedMedId(e.target.value)}
                 required
               >
                 <option value="">-- Select SKU --</option>
                 {medicines.map(m => (
                   <option key={m.id} value={m.id}>{m.name} ({m.stock} {m.unit})</option>
                 ))}
               </select>
             </div>

             <div>
               <label className="text-xs font-semibold text-gray-500 uppercase">Quantity</label>
               <input 
                 type="number" 
                 min="1"
                 className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                 value={quantity || ''}
                 onChange={(e) => setQuantity(parseInt(e.target.value))}
                 required
               />
             </div>

             {type === 'IN' ? (
                <div>
                   <label className="text-xs font-semibold text-gray-500 uppercase">Batch Number</label>
                   <input 
                     type="text" 
                     className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                     value={batch}
                     onChange={(e) => setBatch(e.target.value)}
                     placeholder="e.g. B-202X"
                   />
                </div>
             ) : (
                <div>
                   <label className="text-xs font-semibold text-gray-500 uppercase">Reason</label>
                   <select 
                     className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                     value={reason}
                     onChange={(e) => setReason(e.target.value)}
                   >
                     <option value="Expired">Expired</option>
                     <option value="Damaged">Damaged</option>
                     <option value="Lost">Lost/Stolen</option>
                   </select>
                </div>
             )}

             <Button type="submit" className="w-full mt-2" variant={type === 'IN' ? 'primary' : 'danger'}>
               {type === 'IN' ? 'Add Stock' : 'Remove Stock'}
             </Button>
           </form>
         </div>
       </div>

       {/* Right: History Log */}
       <div className="flex-1 glass-panel rounded-xl border border-gray-200 overflow-hidden flex flex-col">
         <div className="p-4 border-b border-gray-100 bg-gray-50/50">
           <h3 className="font-semibold text-gray-700">Recent Movements</h3>
         </div>
         <div className="overflow-auto flex-1">
           <table className="w-full text-left">
             <thead className="bg-white sticky top-0">
               <tr className="text-xs font-bold text-gray-400 uppercase border-b border-gray-100">
                 <th className="p-4">Date</th>
                 <th className="p-4">Type</th>
                 <th className="p-4">Medicine</th>
                 <th className="p-4 text-center">Qty</th>
                 <th className="p-4">Reason / Batch</th>
               </tr>
             </thead>
             <tbody className="divide-y divide-gray-50">
               {entries.length === 0 && (
                 <tr><td colSpan={5} className="p-8 text-center text-gray-400">No stock history available</td></tr>
               )}
               {entries.map(entry => (
                 <tr key={entry.id} className="hover:bg-blue-50/20">
                   <td className="p-4 text-sm text-gray-500 flex items-center gap-2">
                     <Calendar size={14} />
                     {new Date(entry.date).toLocaleDateString()}
                   </td>
                   <td className="p-4">
                     <span className={clsx("inline-flex items-center gap-1 px-2 py-1 rounded-md text-xs font-bold", 
                       entry.type === 'IN' ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"
                     )}>
                       {entry.type === 'IN' ? <ArrowDownLeft size={12}/> : <ArrowUpRight size={12}/>}
                       {entry.type}
                     </span>
                   </td>
                   <td className="p-4 font-medium text-gray-800">{entry.medicineName}</td>
                   <td className="p-4 text-center font-bold text-gray-600">{entry.quantity}</td>
                   <td className="p-4 text-sm text-gray-500">
                     {entry.type === 'IN' ? (
                       <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs text-gray-600">{entry.batchNumber || 'N/A'}</span>
                     ) : (
                       entry.reason
                     )}
                   </td>
                 </tr>
               ))}
             </tbody>
           </table>
         </div>
       </div>
    </div>
  );
};

export default Stock;

