const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.COUNTER);
  const [showAiModal, setShowAiModal] = useState(false);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [aiLoading, setAiLoading] = useState(false);

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  const handleAiAsk = async () => {
    if (!aiQuery) return;
    setAiLoading(true);
    setAiResponse('');
    const res = await getDrugInfo(aiQuery, 'general');
    setAiResponse(res);
    setAiLoading(false);
  }

  const renderContent = () => {
    switch (activeTab) {
      case Tab.COUNTER:
        return <Counter />;
      case Tab.INVENTORY:
        return <Inventory />;
      case Tab.STOCK:
        return <Stock />;
      case Tab.PATIENTS:
        return <Patients />;
      case Tab.SUPPLIERS:
        return <Suppliers />;
      case Tab.REPORTS:
        return <Reports />;
      case Tab.SETTINGS:
        return <Settings />;
      default:
        return <Counter />;
    }
  };

  return (
    <div className="flex h-screen bg-[#F0F2F5] text-gray-900 font-sans overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={setActiveTab} 
        user={user} 
        onLogout={() => setUser(null)} 
      />

      <main className="flex-1 ml-64 p-6 h-full overflow-hidden relative">
        {/* Header Area within content for extra utility */}
        <div className="absolute top-6 right-6 z-10 print:hidden">
          <button 
             onClick={() => setShowAiModal(true)}
             className="bg-gradient-to-r from-purple-500 to-indigo-600 text-white px-4 py-2 rounded-full shadow-lg hover:shadow-xl transition-all flex items-center gap-2 text-sm font-medium animate-pulse hover:animate-none"
          >
            <MessageSquare size={16} /> Ask AI Consultant
          </button>
        </div>

        {renderContent()}
      </main>

      {/* AI Modal */}
      {showAiModal && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/50 backdrop-blur-sm">
           <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl p-6 border border-purple-100">
             <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                   <div className="w-8 h-8 rounded-lg bg-purple-100 flex items-center justify-center text-purple-600"><MessageSquare size={18}/></div>
                   AI Pharmacy Assistant
                </h3>
                <button onClick={() => setShowAiModal(false)} className="text-gray-400 hover:text-gray-600">✕</button>
             </div>

             <div className="mb-4">
               <p className="text-sm text-gray-500 mb-2">Ask about drug interactions, side effects, or salt info.</p>
               <div className="flex gap-2">
                 <input 
                   className="flex-1 border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-purple-500 outline-none"
                   placeholder="e.g., Side effects of Metformin"
                   value={aiQuery}
                   onChange={(e) => setAiQuery(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && handleAiAsk()}
                 />
                 <Button onClick={handleAiAsk} disabled={aiLoading} className="bg-purple-600 hover:bg-purple-700">
                   {aiLoading ? 'Thinking...' : 'Ask'}
                 </Button>
               </div>
             </div>

             <div className="bg-gray-50 rounded-xl p-4 min-h-[150px] max-h-[300px] overflow-y-auto text-sm text-gray-700 leading-relaxed border border-gray-100">
               {aiResponse ? aiResponse : <span className="text-gray-400 italic">AI response will appear here...</span>}
             </div>
             <p className="text-[10px] text-gray-400 mt-2 text-center">AI advice is for reference only. Consult a professional.</p>
           </div>
        </div>
      )}
    </div>
  );
};

