import React from 'react';
import { Medicine } from '../types';
import { clsx } from 'clsx';
import { Pill } from 'lucide-react';
import { LOW_STOCK_THRESHOLD, EXPIRY_WARNING_DAYS, formatCurrency } from '../constants';

interface MedicineCardProps {
  medicine: Medicine;
  onClick?: (medicine: Medicine) => void;
  actionSlot?: React.ReactNode; // Slot for Edit/Delete buttons in Inventory view
}

export const MedicineCard: React.FC<MedicineCardProps> = ({ medicine, onClick, actionSlot }) => {
  const isLowStock = medicine.stock <= LOW_STOCK_THRESHOLD;
  const isOutOfStock = medicine.stock === 0;

  const expiryDate = new Date(medicine.expiryDate);
  const today = new Date();
  const diffTime = expiryDate.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  const isExpiringSoon = diffDays <= EXPIRY_WARNING_DAYS && diffDays > 0;
  const isExpired = diffDays <= 0;

  return (
    <div 
      onClick={() => !isOutOfStock && onClick && onClick(medicine)}
      className={clsx(
        "relative flex flex-col p-5 rounded-2xl transition-all duration-300 group overflow-hidden",
        "bg-white border hover:shadow-xl hover:-translate-y-1",
        isOutOfStock 
          ? "border-gray-200 opacity-60 grayscale" 
          : isLowStock 
            ? "border-red-200 shadow-red-100" 
            : "border-gray-100 shadow-sm shadow-blue-50"
      )}
    >
      {/* Decorative Background Gradient */}
      <div className={clsx(
        "absolute top-0 right-0 w-32 h-32 rounded-full blur-3xl -mr-16 -mt-16 transition-opacity duration-500",
        isLowStock ? "bg-red-500/10" : "bg-medical-blue/10 group-hover:bg-medical-blue/20"
      )}></div>

      {/* Badges */}
      <div className="absolute top-3 right-3 flex flex-col gap-1 items-end z-10">
        {isExpiringSoon && !isExpired && (
           <span className="bg-orange-50 text-orange-700 text-[10px] font-bold px-2 py-1 rounded-md border border-orange-100 shadow-sm">
             Exp: {diffDays}d
           </span>
        )}
        {isExpired && (
           <span className="bg-red-50 text-red-700 text-[10px] font-bold px-2 py-1 rounded-md border border-red-100 shadow-sm">
             EXPIRED
           </span>
        )}
        {isLowStock && !isOutOfStock && (
           <span className="bg-red-50 text-red-600 text-[10px] font-bold px-2 py-1 rounded-md border border-red-100 shadow-sm animate-pulse">
             LOW STOCK
           </span>
        )}
      </div>

      <div className="mb-4 relative z-10">
        <div className={clsx(
          "w-12 h-12 rounded-xl flex items-center justify-center mb-3 shadow-sm transition-colors", 
          isLowStock ? "bg-red-50 text-red-500" : "bg-blue-50 text-medical-blue group-hover:bg-medical-blue group-hover:text-white"
        )}>
          <Pill size={24} />
        </div>
        <h3 className="font-bold text-gray-800 leading-snug text-lg">{medicine.name}</h3>
        <p className="text-xs text-gray-500 font-medium mt-1 uppercase tracking-wide truncate" title={medicine.genericName}>
          {medicine.genericName}
        </p>
      </div>

      <div className="mt-auto flex items-end justify-between relative z-10">
        <div>
           <p className="text-xs text-gray-400 mb-0.5 font-medium">{medicine.unit}</p>
           <p className="text-xl font-bold text-gray-900">{formatCurrency(medicine.price)}</p>
        </div>
        <div className={clsx("text-xs font-bold px-2.5 py-1.5 rounded-lg border", 
            isOutOfStock ? "bg-gray-100 text-gray-500 border-gray-200" : 
            isLowStock ? "bg-red-50 text-red-700 border-red-100" : "bg-emerald-50 text-emerald-700 border-emerald-100"
        )}>
           {isOutOfStock ? 'OUT' : `${medicine.stock} LEFT`}
        </div>
      </div>

      {/* Action Slot for Edit/Delete buttons */}
      {actionSlot && (
        <div className="mt-4 pt-3 border-t border-gray-100 flex gap-2 relative z-20">
          {actionSlot}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Save, Pill } from 'lucide-react';
import { Button } from './ui/Button';
import { Medicine } from '../types';
import { CATEGORIES, UNITS } from '../constants';
import { v4 as uuidv4 } from 'uuid'; // Fallback if not available, we use Date.now()

interface MedicineFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (medicine: Medicine) => void;
  initialData?: Medicine | null;
}

export const MedicineFormModal: React.FC<MedicineFormModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [formData, setFormData] = useState<Partial<Medicine>>({
    name: '',
    genericName: '',
    category: CATEGORIES[0],
    unit: UNITS[0],
    price: 0,
    stock: 0,
    expiryDate: '',
    batchNumber: '',
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    } else {
      setFormData({
        name: '',
        genericName: '',
        category: CATEGORIES[0],
        unit: UNITS[0],
        price: 0,
        stock: 0,
        expiryDate: '',
        batchNumber: '',
      });
    }
  }, [initialData, isOpen]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const medicine: Medicine = {
      id: initialData?.id || Date.now().toString(),
      name: formData.name || 'New Medicine',
      genericName: formData.genericName || '',
      category: formData.category || 'General',
      unit: (formData.unit as any) || 'Box',
      price: Number(formData.price),
      stock: Number(formData.stock),
      expiryDate: formData.expiryDate || new Date().toISOString().split('T')[0],
      batchNumber: formData.batchNumber || '',
    };
    onSave(medicine);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">

