            width: 100%;
            height: 100%;
            background: white;
            padding: 20px;
          }
          .print\\:hidden {
            display: none !important;
          }
        }
      `}</style>
    </div>
  );
};

export interface Medicine {
  id: string;
  name: string;
  genericName: string; // Salt
  category: string;
  price: number;
  stock: number;
  expiryDate: string;
  batchNumber: string;
  unit: 'Tablet' | 'Strip' | 'Bottle' | 'Box' | 'Injection' | 'Inhaler' | 'Tube';
}

export interface CartItem extends Medicine {
  quantity: number;
  saleUnit: string;     // The unit being sold (e.g. 'Box')
  salePrice: number;    // The price of the unit being sold
  skuDeduction: number; // Stock deduction factor (e.g. 10 if selling Box when SKU is Strip)
}

export interface Sale {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  staffName: string;
  paymentMethod: 'Cash' | 'Card' | 'UPI';
}

export interface StockEntry {
  id: string;
  date: string;
  medicineId: string;
  medicineName: string;
  quantity: number;
  type: 'IN' | 'OUT';
  reason: string; // e.g., 'New Batch', 'Expired', 'Damaged'
  batchNumber?: string;
  supplier?: string;
}

export interface Patient {
  id: string;
  name: string;
  phone: string;
  age?: number;
  gender?: 'Male' | 'Female' | 'Other';
  chronicConditions?: string;
  history: string[]; // Array of sale IDs
}

export interface Supplier {
  id: string;
  name: string;
  contact: string;
  email?: string;
  medicinesSupplied: string[];
}

export interface User {
  username: string;
  role: 'admin' | 'staff';
  permissions: {
    inventory: boolean;
    stock: boolean;
    suppliers: boolean;
    settings: boolean;
  };
}

export enum Tab {
  COUNTER = 'COUNTER',
  INVENTORY = 'INVENTORY',
  STOCK = 'STOCK',
  PATIENTS = 'PATIENTS',
  SUPPLIERS = 'SUPPLIERS',
  REPORTS = 'REPORTS',
  SETTINGS = 'SETTINGS'
}

import React, { useState, useEffect, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, Plus, Minus, CreditCard, Banknote, FileText, X, ChevronRight } from 'lucide-react';
import { Medicine, CartItem, Sale } from '../types';
import { MedicineCard } from '../components/MedicineCard';
import { Button } from '../components/ui/Button';
import { InvoiceModal } from '../components/InvoiceModal';
import { storageService } from '../services/storageService';
import { CURRENCY, CATEGORIES, UNITS, formatCurrency } from '../constants';
import { clsx } from 'clsx';

const Counter: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedUnit, setSelectedUnit] = useState('All');

  const [cart, setCart] = useState<CartItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'Card' | 'UPI'>('Cash');
  const [lastSale, setLastSale] = useState<Sale | null>(null);
  const [showInvoice, setShowInvoice] = useState(false);

  // Unit Selection Modal State
  const [selectedMedForUnit, setSelectedMedForUnit] = useState<Medicine | null>(null);

  useEffect(() => {
    setMedicines(storageService.getMedicines());
  }, []);

  const filteredMedicines = useMemo(() => {
    const term = search.toLowerCase();
    const today = new Date();
    today.setHours(0,0,0,0);

    return medicines.filter(m => {
      // 1. Expiry Check - Hide Expired Items
      const expiry = new Date(m.expiryDate);
      if (expiry < today) return false; 

      // 2. Search
      const matchesSearch = 
        m.name.toLowerCase().includes(term) || 
        m.genericName.toLowerCase().includes(term);

      // 3. Filters
      const matchesCategory = selectedCategory === 'All' || m.category === selectedCategory;
      const matchesUnit = selectedUnit === 'All' || m.unit === selectedUnit;

      return matchesSearch && matchesCategory && matchesUnit;
    });
  }, [medicines, search, selectedCategory, selectedUnit]);

  // Conversion Logic
  const getConversionOptions = (med: Medicine) => {
    const options = [];
    // Always add the base SKU unit
    options.push({ unit: med.unit, price: med.price, factor: 1, label: `Base (${med.unit})` });

    // Assuming standard pharmacy hierarchy: 1 Box = 10 Strips = 100 Tablets
    if (med.unit === 'Box') {
      options.push({ unit: 'Strip', price: med.price / 10, factor: 0.1, label: 'Loose Strip (1/10 Box)' });
      options.push({ unit: 'Tablet', price: med.price / 100, factor: 0.01, label: 'Loose Tablet (1/100 Box)' });
    } else if (med.unit === 'Strip') {
      options.push({ unit: 'Box', price: med.price * 10, factor: 10, label: 'Full Box (10 Strips)' });
      options.push({ unit: 'Tablet', price: med.price / 10, factor: 0.1, label: 'Loose Tablet (1/10 Strip)' });
    } else if (med.unit === 'Tablet') {
      options.push({ unit: 'Strip', price: med.price * 10, factor: 10, label: 'Full Strip (10 Tabs)' });
      options.push({ unit: 'Box', price: med.price * 100, factor: 100, label: 'Full Box (100 Tabs)' });
    }

    return options;
  };

  const handleMedicineClick = (medicine: Medicine) => {
    // Check if conversion applies
    if (['Box', 'Strip', 'Tablet'].includes(medicine.unit)) {
      setSelectedMedForUnit(medicine);
    } else {
      // Direct add for others (Bottle, Tube, etc.)
      addToCart(medicine, medicine.unit, medicine.price, 1);
    }
  };

  const addToCart = (medicine: Medicine, saleUnit: string, salePrice: number, skuDeduction: number) => {
    setCart(prev => {
      // Check if exact same item (same id AND same saleUnit) is in cart
      const existingIndex = prev.findIndex(item => item.id === medicine.id && item.saleUnit === saleUnit);

      if (existingIndex >= 0) {
        const existingItem = prev[existingIndex];
        // Check stock limit
        const totalSkuRequired = (existingItem.quantity + 1) * skuDeduction;
        if (totalSkuRequired > medicine.stock) {
            alert(`Insufficient stock! You have ${medicine.stock} ${medicine.unit}(s).`);
            return prev;
        }

        const newCart = [...prev];
        newCart[existingIndex] = { ...existingItem, quantity: existingItem.quantity + 1 };
        return newCart;
      }

      // Check stock for initial add
      if (skuDeduction > medicine.stock) {
         alert(`Insufficient stock! You need ${skuDeduction} ${medicine.unit}(s) but only have ${medicine.stock}.`);
         return prev;
      }

      return [...prev, { 
        ...medicine, 
        quantity: 1,
        saleUnit,
        salePrice,
        skuDeduction
      }];
    });
    setSelectedMedForUnit(null);
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const updateQuantity = (index: number, delta: number) => {
    setCart(prev => {
      return prev.map((item, i) => {
        if (i === index) {
          const newQty = item.quantity + delta;
          if (newQty <= 0) return item;

          // Check stock
          const med = medicines.find(m => m.id === item.id);
          if (med) {
            const requiredStock = newQty * item.skuDeduction;
            if (requiredStock > med.stock) {
                // Don't update if exceeds stock
                return item;
            }
          }

          return { ...item, quantity: newQty };
        }
        return item;
      });
    });
  };

  const subtotal = cart.reduce((sum, item) => sum + (item.salePrice * item.quantity), 0);
  const total = subtotal;

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const sale: Sale = {
      id: Math.floor(Math.random() * 900000 + 100000).toString(),
      date: new Date().toISOString(),
      items: cart,
      total: total,
      staffName: 'Staff',
      paymentMethod
    };

    storageService.addSale(sale);

    // Update local state
    const updatedMedicines = medicines.map(m => {
      // Find all cart items that correspond to this medicine ID
      const cartItems = cart.filter(c => c.id === m.id);
      if (cartItems.length > 0) {
        const totalDeduction = cartItems.reduce((acc, c) => acc + (c.quantity * c.skuDeduction), 0);
        return { ...m, stock: m.stock - totalDeduction };
      }
      return m;
    });

    setMedicines(updatedMedicines);
    setCart([]);

    setLastSale(sale);
    setShowInvoice(true);
  };

  return (
    <>
      <div className="flex h-full gap-6">
        {/* Left: Medicine Grid */}
        <div className="flex-1 flex flex-col h-full overflow-hidden">
          {/* Controls */}
          <div className="mb-6 flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input 
                type="text" 
                placeholder="Search Brand or Salt..." 
                className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-medical-blue focus:border-transparent outline-none shadow-sm text-base"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                autoFocus
              />
            </div>

            <div className="flex gap-2">
               <select 
                 className="px-4 py-3 rounded-xl border border-gray-200 bg-white text-gray-700 text-sm focus:ring-2 focus:ring-medical-blue outline-none cursor-pointer"
                 value={selectedCategory}
                 onChange={(e) => setSelectedCategory(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
               </select>

               <select 
                 className="px-4 py-3 rounded-xl border border-gray-200 bg-white text-gray-700 text-sm focus:ring-2 focus:ring-medical-blue outline-none cursor-pointer"
                 value={selectedUnit}
                 onChange={(e) => setSelectedUnit(e.target.value)}
               >
                 <option value="All">All Units</option>
                 {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
               </select>
            </div>
          </div>

          {/* Grid */}
          <div className="flex-1 overflow-y-auto pr-2 pb-20">
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
              {filteredMedicines.map(med => (
                <MedicineCard key={med.id} medicine={med} onClick={handleMedicineClick} />
              ))}
            </div>
            {filteredMedicines.length === 0 && (
               <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                 <p>No medicines found.</p>
                 <p className="text-xs mt-2 opacity-70">(Expired items are hidden)</p>
               </div>
            )}
          </div>
        </div>

        {/* Right: Cart */}
        <div className="w-96 glass-panel rounded-2xl flex flex-col border border-gray-200 shadow-xl">
          <div className="p-5 border-b border-gray-100 bg-white/50 rounded-t-2xl">
            <div className="flex items-center justify-between">
              <h2 className="font-bold text-gray-800 flex items-center gap-2">
                <ShoppingCart className="text-medical-blue" /> Current Sale
              </h2>
              <span className="bg-blue-100 text-blue-700 text-xs font-bold px-2 py-1 rounded-lg">
                {cart.length} Items
              </span>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                <ShoppingCart size={48} className="mb-3" />
                <p>Cart is empty</p>
              </div>
            ) : (
              cart.map((item, idx) => (
                <div key={`${item.id}-${item.saleUnit}`} className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between group">
                  <div className="flex-1">
                    <h4 className="font-semibold text-gray-800 text-sm">{item.name}</h4>
                    <p className="text-[10px] text-gray-500">{item.genericName}</p>
                    <div className="flex items-center gap-2 mt-1">
                       <span className="text-xs font-medium text-gray-600 bg-gray-100 px-1.5 py-0.5 rounded">{item.saleUnit}</span>
                       <span className="text-sm font-bold text-medical-blue">{formatCurrency(item.salePrice * item.quantity)}</span>
                    </div>
                  </div>

                  <div className="flex items-center gap-3">
                     <div className="flex items-center bg-gray-50 rounded-lg p-1 border border-gray-200">
                        <button onClick={() => updateQuantity(idx, -1)} className="p-1 hover:bg-gray-200 rounded-md transition-colors"><Minus size={14} /></button>
                        <span className="w-8 text-center font-medium text-sm">{item.quantity}</span>
                        <button onClick={() => updateQuantity(idx, 1)} className="p-1 hover:bg-gray-200 rounded-md transition-colors"><Plus size={14} /></button>
                     </div>
                     <button onClick={() => removeFromCart(idx)} className="text-gray-400 hover:text-red-500 transition-colors">
                       <Trash2 size={18} />
                     </button>
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="p-5 bg-white border-t border-gray-200 rounded-b-2xl">
            <div className="space-y-2 mb-4">
              <div className="flex justify-between text-lg font-bold text-gray-800">
                <span>Total</span>
                <span>{formatCurrency(total)}</span>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2 mb-4">
              {['Cash', 'Card', 'UPI'].map((method) => (
                <button
                  key={method}
                  onClick={() => setPaymentMethod(method as any)}
                  className={clsx(
                    "py-2 rounded-lg text-xs font-semibold border transition-all flex flex-col items-center gap-1",
                    paymentMethod === method 
                      ? "bg-medical-blue text-white border-medical-blue" 
                      : "bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100"
                  )}
                >
                  {method === 'Cash' && <Banknote size={14} />}
                  {method === 'Card' && <CreditCard size={14} />}
                  {method === 'UPI' && <FileText size={14} />}
                  {method}
                </button>
              ))}
            </div>

            <Button 
              className="w-full py-3 text-lg shadow-lg shadow-blue-500/30" 
              onClick={handleCheckout}
              disabled={cart.length === 0}
            >
              Checkout & Print
            </Button>
          </div>
        </div>
      </div>

      <InvoiceModal 
        sale={lastSale} 
        onClose={() => setShowInvoice(false)} 
      />
      {showInvoice && <div className="fixed inset-0 z-40 bg-black/20" onClick={() => setShowInvoice(false)}/>}

      {/* Unit Selection Modal */}
      {selectedMedForUnit && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm overflow-hidden">
             <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                <h3 className="font-bold text-gray-800">Select Sales Unit</h3>
                <button onClick={() => setSelectedMedForUnit(null)}><X size={20} className="text-gray-400"/></button>
             </div>
             <div className="p-4">
               <div className="mb-4 text-center">
                 <h4 className="font-bold text-lg text-medical-blue">{selectedMedForUnit.name}</h4>
                 <p className="text-xs text-gray-500">Stock: {selectedMedForUnit.stock} {selectedMedForUnit.unit}s</p>
               </div>
               <div className="space-y-2">
                 {getConversionOptions(selectedMedForUnit).map((opt) => (
                   <button 
                     key={opt.unit}
                     onClick={() => addToCart(selectedMedForUnit, opt.unit, opt.price, opt.factor)}
                     className="w-full flex items-center justify-between p-3 rounded-xl border border-gray-200 hover:border-medical-blue hover:bg-blue-50 transition-all group"
                   >
                     <div className="text-left">
                       <span className="block font-semibold text-gray-800">{opt.label}</span>
                       <span className="text-xs text-gray-500">Unit: {opt.unit}</span>
                     </div>
                     <div className="flex items-center gap-2">
                       <span className="font-bold text-medical-blue">{formatCurrency(opt.price)}</span>
                       <ChevronRight size={16} className="text-gray-300 group-hover:text-medical-blue" />
                     </div>
                   </button>
                 ))}
               </div>
             </div>
           </div>
        </div>
      )}
    </>
  );
};

export default Counter;

import React, { useState, useEffect } from 'react';
import { Plus, Search, Edit, Trash } from 'lucide-react';
import { Medicine } from '../types';
import { storageService } from '../services/storageService';
import { Button } from '../components/ui/Button';
import { PinModal } from '../components/PinModal';
import { MedicineCard } from '../components/MedicineCard';
import { MedicineFormModal } from '../components/MedicineFormModal';
import { MASTER_PIN } from '../constants';

const Inventory: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');

  // Modals & Active State
  const [isPinModalOpen, setPinModalOpen] = useState(false);
  const [isFormModalOpen, setFormModalOpen] = useState(false);
  const [pendingAction, setPendingAction] = useState<(() => void) | null>(null);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);

  useEffect(() => {
    setMedicines(storageService.getMedicines());
  }, []);

  const filtered = medicines.filter(m => {
    // Search Filter
    const matchesSearch = 
      m.name.toLowerCase().includes(search.toLowerCase()) ||
      m.genericName.toLowerCase().includes(search.toLowerCase());

    // Expiry Filter - Hide Expired Items
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(m.expiryDate);
    const isNotExpired = expiry >= today;

    return matchesSearch && isNotExpired;
  });

  // --- Handlers ---

  const handleAddNew = () => {
    setPendingAction(() => () => {
      setEditingMedicine(null); // Clear for new
      setFormModalOpen(true);
    });
    setPinModalOpen(true);
  };

  const handleEdit = (med: Medicine) => {
    setPendingAction(() => () => {
      setEditingMedicine(med);
      setFormModalOpen(true);
    });
    setPinModalOpen(true);
  };

  const handleDelete = (id: string) => {
    setPendingAction(() => () => {
      if(confirm("Are you sure you want to delete this medicine?")) {
        const updated = medicines.filter(m => m.id !== id);
        storageService.saveMedicines(updated);
        setMedicines(updated);
      }
    });
    setPinModalOpen(true);
  };

  const handleSaveMedicine = (med: Medicine) => {
    let updatedList;
    if (editingMedicine) {
      // Update existing
      updatedList = medicines.map(m => m.id === med.id ? med : m);
    } else {
      // Add new
      updatedList = [med, ...medicines];
    }
    storageService.saveMedicines(updatedList);
    setMedicines(updatedList);
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Inventory Manager</h2>
          <p className="text-gray-500 text-sm">Create, edit, and organize medicine SKUs.</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
             <input 
               type="text" 
               placeholder="Search inventory..." 
               className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none shadow-sm"
               value={search}
               onChange={(e) => setSearch(e.target.value)}
             />
          </div>
          <Button onClick={handleAddNew} className="gap-2 shadow-lg shadow-blue-500/30 whitespace-nowrap">
            <Plus size={18} /> New SKU
          </Button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pr-2 pb-20">
        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-5">
           {filtered.length === 0 && (
             <div className="col-span-full py-20 text-center text-gray-400">
               No medicines found matching your search (Expired items hidden).
             </div>
           )}
           {filtered.map(med => (
             <MedicineCard 
               key={med.id} 
               medicine={med} 
               actionSlot={
                 <>
                   <button 
                     onClick={(e) => { e.stopPropagation(); handleEdit(med); }} 
                     className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-blue-50 text-medical-blue hover:bg-blue-100 text-xs font-bold transition-colors"
                   >
                     <Edit size={14} /> Edit
                   </button>
                   <button 
                     onClick={(e) => { e.stopPropagation(); handleDelete(med.id); }} 
                     className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-red-50 text-red-500 hover:bg-red-100 text-xs font-bold transition-colors"
                   >
                     <Trash size={14} /> Del
                   </button>
                 </>
               }
             />
           ))}
        </div>
      </div>

      {/* Security Check */}
      <PinModal 
        isOpen={isPinModalOpen}
        onClose={() => setPinModalOpen(false)}
        requiredPin={MASTER_PIN}
        onSuccess={() => {
          if (pendingAction) pendingAction();
          setPendingAction(null);
        }}
        title="Admin Authorization"
      />

      {/* Add/Edit Form */}
      <MedicineFormModal 
        isOpen={isFormModalOpen}
        onClose={() => setFormModalOpen(false)}
        onSave={handleSaveMedicine}
        initialData={editingMedicine}
      />
    </div>
  );
};

export default Inventory;

