import React, { useState, useEffect } from 'react';
import { Plus, Search, Edit, Trash } from 'lucide-react';
import { Medicine } from '../types';
import { storageService } from '../services/storageService';
import { Button } from '../components/ui/Button';
import { MedicineCard } from '../components/MedicineCard';
import { MedicineFormModal } from '../components/MedicineFormModal';

const Inventory: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');

  // Modals & Active State
  const [isFormModalOpen, setFormModalOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);

  useEffect(() => {
    setMedicines(storageService.getMedicines());
  }, []);

  const filtered = medicines.filter(m => {
    // Search Filter
    const matchesSearch = 
      m.name.toLowerCase().includes(search.toLowerCase()) ||
      m.genericName.toLowerCase().includes(search.toLowerCase());

    // Expiry Filter - Hide Expired Items
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(m.expiryDate);
    const isNotExpired = expiry >= today;

    return matchesSearch && isNotExpired;
  });

  // --- Handlers ---

  const handleAddNew = () => {
    setEditingMedicine(null); // Clear for new
    setFormModalOpen(true);
  };

  const handleEdit = (med: Medicine) => {
    setEditingMedicine(med);
    setFormModalOpen(true);
  };

  const handleDelete = (id: string) => {
    if(confirm("Are you sure you want to delete this medicine?")) {
      const updated = medicines.filter(m => m.id !== id);
      storageService.saveMedicines(updated);
      setMedicines(updated);
    }
  };

  const handleSaveMedicine = (med: Medicine) => {
    let updatedList;
    if (editingMedicine) {
      // Update existing
      updatedList = medicines.map(m => m.id === med.id ? med : m);
    } else {
      // Add new
      updatedList = [med, ...medicines];
    }
    storageService.saveMedicines(updatedList);
    setMedicines(updatedList);
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Inventory Manager</h2>
          <p className="text-gray-500 text-sm">Create, edit, and organize medicine SKUs.</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
             <input 
               type="text" 
               placeholder="Search inventory..." 
               className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none shadow-sm"
               value={search}
               onChange={(e) => setSearch(e.target.value)}
             />
          </div>
          <Button onClick={handleAddNew} className="gap-2 shadow-lg shadow-blue-500/30 whitespace-nowrap">
            <Plus size={18} /> New SKU
          </Button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pr-2 pb-20">
        <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-5">
           {filtered.length === 0 && (
             <div className="col-span-full py-20 text-center text-gray-400">
               No medicines found matching your search (Expired items hidden).
             </div>
           )}
           {filtered.map(med => (
             <MedicineCard 
               key={med.id} 
               medicine={med} 
               actionSlot={
                 <>
                   <button 
                     onClick={(e) => { e.stopPropagation(); handleEdit(med); }} 
                     className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-blue-50 text-medical-blue hover:bg-blue-100 text-xs font-bold transition-colors"
                   >
                     <Edit size={14} /> Edit
                   </button>
                   <button 
                     onClick={(e) => { e.stopPropagation(); handleDelete(med.id); }} 
                     className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-red-50 text-red-500 hover:bg-red-100 text-xs font-bold transition-colors"
                   >
                     <Trash size={14} /> Del
                   </button>
                 </>
               }
             />
           ))}
        </div>
      </div>

      {/* Add/Edit Form */}
      <MedicineFormModal 
        isOpen={isFormModalOpen}
        onClose={() => setFormModalOpen(false)}
        onSave={handleSaveMedicine}
        initialData={editingMedicine}
      />
    </div>
  );
};

