  return (
    <aside className="w-64 glass-panel h-screen flex flex-col fixed left-0 top-0 z-40 border-r border-white/40 shadow-xl bg-white/60 backdrop-blur-xl">
      <div className="p-6 flex items-center gap-3 border-b border-gray-100/50">
