              )}
            >
              <Icon size={20} className={isActive ? "text-white" : "text-gray-400 group-hover:text-gray-900"} />
              <span className="font-semibold text-sm">{item.label}</span>

              {/* Badge for Stock Tab if Alerts exist */}
              {item.id === Tab.STOCK && (lowStockCount > 0 || expiringCount > 0) && !isActive && (
                <span className="absolute right-4 w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>
              )}
            </button>
          );
        })}

        {/* Notification System Area */}
        {(lowStockCount > 0 || expiringCount > 0) && (
          <div className="mt-8 mx-2 p-4 rounded-2xl bg-white/80 border border-red-100 shadow-[0_8px_30px_rgb(0,0,0,0.04)] animate-in slide-in-from-left-4 duration-500">
            <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <AlertCircle size={12} /> System Alerts
