import React, { useEffect, useState } from 'react';
import { storageService } from '../services/storageService';
import { Sale, Medicine } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';
import { formatCurrency, LOW_STOCK_THRESHOLD, EXPIRY_WARNING_DAYS } from '../constants';

const Reports: React.FC = () => {
  const [sales, setSales] = useState<Sale[]>([]);
  const [medicines, setMedicines] = useState<Medicine[]>([]);

  // Real-time Data Loading
  useEffect(() => {
    setSales(storageService.getSales());
    setMedicines(storageService.getMedicines());
  }, []);

  // --- Calculations ---

  // 1. Financials
  const totalRevenue = sales.reduce((acc, curr) => acc + curr.total, 0);
  const totalTransactions = sales.length;

  // 2. Inventory Health
  const lowStockCount = medicines.filter(m => m.stock <= LOW_STOCK_THRESHOLD && m.stock > 0).length;
  const expiredCount = medicines.filter(m => {
    const today = new Date();
    today.setHours(0,0,0,0);
    return new Date(m.expiryDate) < today;
  }).length;

  // 3. Weekly Sales Trend (Last 7 Days)
  const getWeeklyData = () => {
    const data = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const dayStr = d.toISOString().split('T')[0];

      const daySales = sales.filter(s => s.date.startsWith(dayStr));
      const total = daySales.reduce((sum, s) => sum + s.total, 0);

      data.push({
        name: d.toLocaleDateString('en-US', { weekday: 'short' }),
        sales: total,
        date: dayStr
      });
    }
    return data;
  };

  // 4. Category Performance
  const getCategoryData = () => {
    const catMap: Record<string, number> = {};
    sales.forEach(sale => {
      sale.items.forEach(item => {
        if (!catMap[item.category]) catMap[item.category] = 0;
        catMap[item.category] += (item.salePrice * item.quantity);
      });
    });

    return Object.keys(catMap).map(key => ({
      name: key,
      value: catMap[key]
    })).sort((a, b) => b.value - a.value).slice(0, 6); // Top 6
  };

  const weeklyData = getWeeklyData();
  const categoryData = getCategoryData();

  // Growth Logic (Simple comparison vs previous week average approximation)
  const todaySales = weeklyData[weeklyData.length - 1].sales;
  const avgSales = weeklyData.reduce((a, b) => a + b.sales, 0) / 7;
  const performanceColor = todaySales >= avgSales ? 'text-green-600 bg-green-100' : 'text-orange-600 bg-orange-100';

  return (
    <div className="h-full overflow-y-auto pb-10">
       <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center gap-2">
         Real-time Analytics
       </h2>

       <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Total Revenue</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{formatCurrency(totalRevenue)}</h3>
           <span className={`text-[10px] font-bold px-2 py-1 rounded-full mt-3 inline-block ${performanceColor}`}>
             {todaySales >= avgSales ? 'Above Average' : 'Below Average'}
           </span>
         </div>

         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Transactions</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{totalTransactions}</h3>
           <span className="text-[10px] font-bold text-blue-600 bg-blue-100 px-2 py-1 rounded-full mt-3 inline-block">Lifetime Sales</span>
         </div>

         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Low Stock SKUs</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{lowStockCount}</h3>
           <span className="text-[10px] font-bold text-orange-600 bg-orange-100 px-2 py-1 rounded-full mt-3 inline-block">Reorder Soon</span>
         </div>

         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Expired Items</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{expiredCount}</h3>
           <span className="text-[10px] font-bold text-red-600 bg-red-100 px-2 py-1 rounded-full mt-3 inline-block">Remove from Shelf</span>
         </div>
       </div>

       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
         {/* Line Chart */}
         <div className="bg-white/60 backdrop-blur-xl p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-white h-96">
            <h4 className="font-bold text-gray-800 mb-6 text-lg">Revenue Trend (7 Days)</h4>
            <ResponsiveContainer width="100%" height="100%" className="-ml-4">
              <LineChart data={weeklyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 12, fontWeight: 600}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 12, fontWeight: 600}} tickFormatter={(val) => `${val/1000}k`} />
                <Tooltip 
                  cursor={{stroke: '#007BFF', strokeWidth: 2, strokeDasharray: '5 5'}}
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)', padding: '12px'}} 
                  itemStyle={{color: '#1F2937', fontWeight: 'bold'}}
                  formatter={(value: number) => [formatCurrency(value), 'Revenue']}
                />
                <Line 
                  type="monotone" 
                  dataKey="sales" 
                  stroke="#007BFF" 
                  strokeWidth={4} 
                  dot={{r: 4, fill: 'white', stroke: '#007BFF', strokeWidth: 2}} 
                  activeDot={{r: 8, fill: '#007BFF', stroke: 'white', strokeWidth: 2}} 
                />
              </LineChart>
            </ResponsiveContainer>
         </div>

         {/* Bar Chart */}
         <div className="bg-white/60 backdrop-blur-xl p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-white h-96">
            <h4 className="font-bold text-gray-800 mb-6 text-lg">Top Categories by Revenue</h4>
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%" className="-ml-4">
                <BarChart data={categoryData} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#E5E7EB" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{fill: '#6B7280', fontSize: 11, fontWeight: 600}} width={80} />
                  <Tooltip 
                    cursor={{fill: '#F3F4F6', radius: 8}} 
                    contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)', padding: '12px'}}
                    itemStyle={{color: '#1F2937', fontWeight: 'bold'}}
                    formatter={(value: number) => [formatCurrency(value), 'Sales']}
                  />
                  <Bar dataKey="value" fill="#3B82F6" radius={[0, 8, 8, 0]} barSize={24} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400 font-medium">
                No sales data available yet.
              </div>
            )}
         </div>
       </div>
    </div>
  );
};

export default Reports;

