  );
};

import React from 'react';
import { Medicine } from '../types';
import { clsx } from 'clsx';
import { Pill, Activity } from 'lucide-react';
import { LOW_STOCK_THRESHOLD, EXPIRY_WARNING_DAYS, formatCurrency } from '../constants';

interface MedicineCardProps {
  medicine: Medicine;
  onClick?: (medicine: Medicine) => void;
  actionSlot?: React.ReactNode; 
}

export const MedicineCard: React.FC<MedicineCardProps> = ({ medicine, onClick, actionSlot }) => {
  const isLowStock = medicine.stock <= LOW_STOCK_THRESHOLD;
  const isOutOfStock = medicine.stock === 0;

  const expiryDate = new Date(medicine.expiryDate);
  const today = new Date();
  const diffTime = expiryDate.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  const isExpiringSoon = diffDays <= EXPIRY_WARNING_DAYS && diffDays > 0;
  const isExpired = diffDays <= 0;

  return (
    <div 
      onClick={() => !isOutOfStock && onClick && onClick(medicine)}
      className={clsx(
        "relative flex flex-row items-stretch gap-4 p-4 rounded-2xl transition-all duration-300 group overflow-hidden cursor-pointer",
        "bg-white/90 backdrop-blur-xl border border-white/60",
        "hover:shadow-[0_8px_30px_rgb(0,0,0,0.12)] hover:border-blue-200 hover:scale-[1.01]",
        isOutOfStock 
          ? "opacity-60 grayscale" 
          : "shadow-sm"
      )}
    >
      {/* Left: Icon & visual indicator */}
      <div className="flex flex-col items-center gap-2 shrink-0">
        <div className={clsx(
          "w-14 h-14 rounded-2xl flex items-center justify-center transition-colors duration-300 shadow-sm border border-white",
          isLowStock ? "bg-red-50 text-red-500" : "bg-blue-50 text-blue-600 group-hover:bg-blue-600 group-hover:text-white"
        )}>
          <Pill size={24} strokeWidth={2} />
        </div>

        {/* Status Badge */}
        {isOutOfStock ? (
          <span className="w-full text-center text-[10px] font-bold text-gray-500 bg-gray-100 py-1 rounded-lg uppercase tracking-wider">Out</span>
        ) : isLowStock ? (
          <span className="w-full text-center text-[10px] font-bold text-red-600 bg-red-50 py-1 rounded-lg uppercase tracking-wider animate-pulse border border-red-100">Low</span>
        ) : (
          <span className="w-full text-center text-[10px] font-bold text-emerald-600 bg-emerald-50 py-1 rounded-lg uppercase tracking-wider border border-emerald-100">Ok</span>
        )}
      </div>

      {/* Right: Content */}
      <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
        <div>
           <div className="flex justify-between items-start gap-2">
             <h3 className="font-bold text-gray-900 leading-tight truncate text-base group-hover:text-blue-700 transition-colors">
               {medicine.name}
             </h3>
             {isExpiringSoon && !isExpired && (
               <span className="shrink-0 text-[9px] font-bold text-orange-600 bg-orange-100 px-1.5 py-0.5 rounded border border-orange-200">Exp {diffDays}d</span>
             )}
           </div>

           <p className="text-xs text-gray-500 font-medium truncate flex items-center gap-1 mt-1">
             <Activity size={10} className="text-blue-400" />
             {medicine.genericName}
           </p>
        </div>

        <div className="mt-3 pt-3 border-t border-gray-100 flex items-end justify-between">
           <div className="flex flex-col">
              <span className="text-[9px] font-bold text-gray-400 uppercase tracking-wider mb-0.5">{medicine.unit}</span>
              <span className="text-lg font-black text-gray-900 leading-none tracking-tight">{formatCurrency(medicine.price)}</span>
           </div>

           {actionSlot ? (
              <div className="flex gap-2 ml-2 w-1/2 justify-end" onClick={(e) => e.stopPropagation()}>
                 {actionSlot}
              </div>
           ) : (
              !isOutOfStock && (
                <div className="text-xs font-semibold text-gray-500 bg-gray-50 px-2 py-1 rounded-lg border border-gray-100">
                   Qty: {medicine.stock}
                </div>
              )
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, Plus, Minus, CreditCard, Banknote, FileText, X, ChevronRight, Package2 } from 'lucide-react';
import { Medicine, CartItem, Sale } from '../types';
import { MedicineCard } from '../components/MedicineCard';
import { Button } from '../components/ui/Button';
import { InvoiceModal } from '../components/InvoiceModal';
import { storageService } from '../services/storageService';
import { CURRENCY, CATEGORIES, UNITS, formatCurrency } from '../constants';
import { clsx } from 'clsx';

const Counter: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedUnit, setSelectedUnit] = useState('All');

  const [cart, setCart] = useState<CartItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'Card' | 'UPI'>('Cash');
  const [lastSale, setLastSale] = useState<Sale | null>(null);
  const [showInvoice, setShowInvoice] = useState(false);

  // Unit Selection Modal State
  const [selectedMedForUnit, setSelectedMedForUnit] = useState<Medicine | null>(null);

  // Load initial data
  const loadData = () => {
    setMedicines(storageService.getMedicines());
  };

  useEffect(() => {
    loadData();
  }, []);

  const filteredMedicines = useMemo(() => {
    const term = search.toLowerCase();
    const today = new Date();
    today.setHours(0,0,0,0);

    return medicines.filter(m => {
      // 1. Expiry Check - Hide Expired Items
      const expiry = new Date(m.expiryDate);
      if (expiry < today) return false; 

      // 2. Search
      const matchesSearch = 
        m.name.toLowerCase().includes(term) || 
        m.genericName.toLowerCase().includes(term);

      // 3. Filters
      const matchesCategory = selectedCategory === 'All' || m.category === selectedCategory;
      const matchesUnit = selectedUnit === 'All' || m.unit === selectedUnit;

      return matchesSearch && matchesCategory && matchesUnit;
    });
  }, [medicines, search, selectedCategory, selectedUnit]);

  // Conversion Logic
  const getConversionOptions = (med: Medicine) => {
    const options = [];
    options.push({ unit: med.unit, price: med.price, factor: 1, label: `Base (${med.unit})` });

    if (med.unit === 'Box') {
      options.push({ unit: 'Strip', price: med.price / 10, factor: 0.1, label: 'Loose Strip (1/10 Box)' });
      options.push({ unit: 'Tablet', price: med.price / 100, factor: 0.01, label: 'Loose Tablet (1/100 Box)' });
    } else if (med.unit === 'Strip') {
      options.push({ unit: 'Box', price: med.price * 10, factor: 10, label: 'Full Box (10 Strips)' });
      options.push({ unit: 'Tablet', price: med.price / 10, factor: 0.1, label: 'Loose Tablet (1/10 Strip)' });
    } else if (med.unit === 'Tablet') {
      options.push({ unit: 'Strip', price: med.price * 10, factor: 10, label: 'Full Strip (10 Tabs)' });
      options.push({ unit: 'Box', price: med.price * 100, factor: 100, label: 'Full Box (100 Tabs)' });
    }

    return options;
  };

  const handleMedicineClick = (medicine: Medicine) => {
    if (['Box', 'Strip', 'Tablet'].includes(medicine.unit)) {
      setSelectedMedForUnit(medicine);
    } else {
      addToCart(medicine, medicine.unit, medicine.price, 1);
    }
  };

  const addToCart = (medicine: Medicine, saleUnit: string, salePrice: number, skuDeduction: number) => {
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.id === medicine.id && item.saleUnit === saleUnit);

      if (existingIndex >= 0) {
        const existingItem = prev[existingIndex];
        const totalSkuRequired = (existingItem.quantity + 1) * skuDeduction;
        if (totalSkuRequired > medicine.stock) {
            alert(`Insufficient stock! You have ${medicine.stock} ${medicine.unit}(s).`);
            return prev;
        }

        const newCart = [...prev];
        newCart[existingIndex] = { ...existingItem, quantity: existingItem.quantity + 1 };
        return newCart;
      }

      if (skuDeduction > medicine.stock) {
         alert(`Insufficient stock! You need ${skuDeduction} ${medicine.unit}(s) but only have ${medicine.stock}.`);
         return prev;
      }

      return [...prev, { 
        ...medicine, 
        quantity: 1,
        saleUnit,
        salePrice,
        skuDeduction
      }];
    });
    setSelectedMedForUnit(null);
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const updateQuantity = (index: number, newQty: number) => {
    if (newQty < 0) return; // Prevent negative inputs

    setCart(prev => {
      return prev.map((item, i) => {
        if (i === index) {
          if (newQty === 0) return item; 

          // Check stock
          const med = medicines.find(m => m.id === item.id);
          if (med) {
            const requiredStock = newQty * item.skuDeduction;
            if (requiredStock > med.stock) {
                return item;
            }
          }
          return { ...item, quantity: newQty };
        }
        return item;
      });
    });
  };

  const subtotal = cart.reduce((sum, item) => sum + (item.salePrice * item.quantity), 0);
  const total = subtotal;

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const sale: Sale = {
      id: Math.floor(Math.random() * 900000 + 100000).toString(),
      date: new Date().toISOString(),
      items: cart,
      total: total,
      staffName: 'Staff',
      paymentMethod
    };

    // The Service now handles:
    // 1. Saving Sale
    // 2. Decrementing Stock
    // 3. Creating "Sale" log in Stock History
    storageService.addSale(sale);

    // Refresh local state to reflect new stock levels
    loadData();

    setCart([]);
    setLastSale(sale);
    setShowInvoice(true);
  };

  return (
    <>
      <div className="flex h-full gap-6">
        {/* Left: Medicine Grid */}
        <div className="flex-1 flex flex-col h-full overflow-hidden">
          {/* Controls */}
          <div className="mb-6 flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input 
                type="text" 
                placeholder="Search Brand or Salt..." 
                className="w-full pl-12 pr-4 py-3.5 rounded-2xl border-none bg-white shadow-sm focus:ring-2 focus:ring-blue-100 outline-none text-base text-gray-700"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                autoFocus
              />
            </div>

            <div className="flex gap-2">
               <select 
                 className="px-4 py-3 rounded-2xl border-none bg-white shadow-sm text-gray-600 text-sm focus:ring-2 focus:ring-blue-100 outline-none cursor-pointer"
                 value={selectedCategory}
                 onChange={(e) => setSelectedCategory(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
               </select>

               <select 
                 className="px-4 py-3 rounded-2xl border-none bg-white shadow-sm text-gray-600 text-sm focus:ring-2 focus:ring-blue-100 outline-none cursor-pointer"
                 value={selectedUnit}
                 onChange={(e) => setSelectedUnit(e.target.value)}
               >
                 <option value="All">All Units</option>
                 {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
               </select>
            </div>
          </div>

          {/* Grid */}
          <div className="flex-1 overflow-y-auto pr-2 pb-20">
            {/* Horizontal Grid Layout Adjustment */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4 gap-4 p-1">
              {filteredMedicines.map(med => (
                <MedicineCard key={med.id} medicine={med} onClick={handleMedicineClick} />
              ))}
            </div>
            {filteredMedicines.length === 0 && (
               <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                 <Package2 size={48} className="mb-4 opacity-50" />
                 <p className="font-medium">No medicines found.</p>
                 <p className="text-xs mt-2 opacity-70">(Expired items are hidden)</p>
               </div>
            )}
          </div>
        </div>

        {/* Right: Cart */}
        <div className="w-96 glass-panel rounded-[2rem] flex flex-col border border-white/60 shadow-xl overflow-hidden bg-white/80 backdrop-blur-2xl">
          <div className="p-6 border-b border-gray-100 bg-white/40">
            <div className="flex items-center justify-between">
              <h2 className="font-extrabold text-gray-800 text-lg flex items-center gap-2">
                <ShoppingCart className="text-medical-blue fill-current" size={20} /> Current Sale
              </h2>
              <span className="bg-blue-600 text-white text-xs font-bold px-2.5 py-1 rounded-full shadow-lg shadow-blue-500/30">
                {cart.length}
              </span>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                <ShoppingCart size={48} className="mb-3" />
                <p>Cart is empty</p>
              </div>
            ) : (
              cart.map((item, idx) => (
                <div key={`${item.id}-${item.saleUnit}`} className="bg-white p-4 rounded-2xl border border-gray-50 shadow-[0_4px_20px_rgb(0,0,0,0.03)] flex flex-col gap-3 group transition-all hover:scale-[1.01]">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold text-gray-800 text-sm leading-tight">{item.name}</h4>
                      <p className="text-[10px] text-gray-500 font-medium">{item.genericName}</p>
                    </div>
                    <button onClick={() => removeFromCart(idx)} className="text-gray-300 hover:text-red-500 transition-colors p-1">
                       <Trash2 size={16} />
                    </button>
                  </div>

                  <div className="flex items-center justify-between">
                     <div className="flex items-center gap-2">
                        <span className="text-[10px] font-bold text-gray-500 bg-gray-100 px-2 py-1 rounded-md uppercase tracking-wider">{item.saleUnit}</span>
                        <div className="flex items-center bg-gray-50 rounded-xl p-0.5 border border-gray-200">
                           <button onClick={() => updateQuantity(idx, item.quantity - 1)} className="w-7 h-7 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-600"><Minus size={12} /></button>
                           <input 
                             type="number"
                             min="1"
                             className="w-10 text-center bg-transparent text-sm font-bold text-gray-800 outline-none p-0 border-none focus:ring-0"
                             value={item.quantity}
                             onChange={(e) => {
                               const val = parseInt(e.target.value);
                               if (!isNaN(val)) updateQuantity(idx, val);
                             }}
                           />
                           <button onClick={() => updateQuantity(idx, item.quantity + 1)} className="w-7 h-7 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-600"><Plus size={12} /></button>
                        </div>
                     </div>
                     <span className="text-base font-bold text-medical-blue">{formatCurrency(item.salePrice * item.quantity)}</span>
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="p-6 bg-white border-t border-gray-100">
            <div className="space-y-1 mb-6">
              <div className="flex justify-between text-xs text-gray-500 font-medium">
                <span>Subtotal</span>
                <span>{formatCurrency(subtotal)}</span>
              </div>
              <div className="flex justify-between text-2xl font-black text-gray-900">
                <span>Total</span>
                <span>{formatCurrency(total)}</span>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2 mb-6">
              {['Cash', 'Card', 'UPI'].map((method) => (
                <button
                  key={method}
                  onClick={() => setPaymentMethod(method as any)}
                  className={clsx(
                    "py-2.5 rounded-xl text-[10px] font-bold border transition-all flex flex-col items-center gap-1 uppercase tracking-wide",
                    paymentMethod === method 
                      ? "bg-gray-900 text-white border-gray-900 shadow-lg" 
                      : "bg-white text-gray-500 border-gray-100 hover:border-gray-300 hover:bg-gray-50"
                  )}
                >
                  {method === 'Cash' && <Banknote size={16} />}
                  {method === 'Card' && <CreditCard size={16} />}
                  {method === 'UPI' && <FileText size={16} />}
                  {method}
                </button>
              ))}
            </div>

            <Button 
              className="w-full py-4 text-base font-bold rounded-xl shadow-[0_10px_20px_-5px_rgba(37,99,235,0.4)] bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-700 hover:to-blue-600 transform active:scale-[0.98] transition-all" 
              onClick={handleCheckout}
              disabled={cart.length === 0}
            >
              Confirm & Print Receipt
            </Button>
          </div>
        </div>
      </div>

      {showInvoice && lastSale && (
        <InvoiceModal 
          sale={lastSale} 
          onClose={() => setShowInvoice(false)} 
        />
      )}

      {/* Unit Selection Modal */}
      {selectedMedForUnit && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-md p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-sm overflow-hidden border border-white/50">
             <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                <h3 className="font-bold text-gray-900 text-lg">Select Unit</h3>
                <button onClick={() => setSelectedMedForUnit(null)} className="p-1 hover:bg-gray-200 rounded-full transition-colors"><X size={20} className="text-gray-500"/></button>
             </div>
             <div className="p-5 bg-white/80">
               <div className="mb-6 text-center">
                 <h4 className="font-black text-xl text-gray-800">{selectedMedForUnit.name}</h4>
                 <div className="inline-block mt-2 px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-xs font-bold">
                   Available: {selectedMedForUnit.stock} {selectedMedForUnit.unit}s
                 </div>
               </div>
               <div className="space-y-3">
                 {getConversionOptions(selectedMedForUnit).map((opt) => (
                   <button 
                     key={opt.unit}
                     onClick={() => addToCart(selectedMedForUnit, opt.unit, opt.price, opt.factor)}
                     className="w-full flex items-center justify-between p-4 rounded-2xl border border-gray-100 bg-white hover:border-blue-500 hover:shadow-lg hover:shadow-blue-500/10 transition-all group"
                   >
                     <div className="text-left">
                       <span className="block font-bold text-gray-800 text-sm group-hover:text-blue-600 transition-colors">{opt.label}</span>
                       <span className="text-[10px] text-gray-400 font-semibold uppercase tracking-wider">Sell as {opt.unit}</span>
                     </div>
                     <div className="flex items-center gap-3">
                       <span className="font-bold text-gray-900 text-lg">{formatCurrency(opt.price)}</span>
                       <ChevronRight size={18} className="text-gray-300 group-hover:text-blue-500" />
                     </div>
                   </button>
                 ))}
               </div>
             </div>
           </div>
        </div>
      )}
    </>
  );
};

