import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Tab, User } from './types';
import Login from './pages/Login';
import Counter from './pages/Counter';
import Inventory from './pages/Inventory';
import Reports from './pages/Reports';
import Stock from './pages/Stock';
import Patients from './pages/Patients';
import Suppliers from './pages/Suppliers';
import Settings from './pages/Settings';
import { MessageSquare, Sparkles, WifiOff, Wifi } from 'lucide-react';
import { getDrugInfo } from './services/geminiService';
import { Button } from './components/ui/Button';

const App: React.FC = () => {
  // Initialize with Admin user to make Login window inactive (bypass it)
  const [user, setUser] = useState<User | null>({
    username: 'admin',
    role: 'admin',
    permissions: { 
      inventory: true, 
      stock: true, 
      suppliers: true, 
      settings: true 
    }
  });

  const [activeTab, setActiveTab] = useState<Tab>(Tab.COUNTER);
  const [showAiModal, setShowAiModal] = useState(false);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [aiLoading, setAiLoading] = useState(false);

  // Offline Mode State
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  const handleAiAsk = async () => {
    if (!aiQuery || !isOnline) return;
    setAiLoading(true);
    setAiResponse('');
    const res = await getDrugInfo(aiQuery, 'general');
    setAiResponse(res);
    setAiLoading(false);
  }

  const renderContent = () => {
    switch (activeTab) {
      case Tab.COUNTER:
        return <Counter />;
      case Tab.INVENTORY:
        return <Inventory />;
      case Tab.STOCK:
        return <Stock />;
      case Tab.PATIENTS:
        return <Patients />;
      case Tab.SUPPLIERS:
        return <Suppliers />;
      case Tab.REPORTS:
        return <Reports />;
      case Tab.SETTINGS:
        return <Settings />;
      default:
        return <Counter />;
    }
  };

  return (
    <div className="flex h-screen bg-[#F0F2F5] text-gray-900 font-sans overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={setActiveTab} 
        user={user} 
        onLogout={() => setUser(null)} 
      />

      <main className="flex-1 ml-64 p-6 h-full overflow-hidden relative flex flex-col">
        {/* Offline Banner */}
        {!isOnline && (
          <div className="mb-4 bg-gray-800 text-white px-4 py-2 rounded-xl flex items-center justify-between shadow-lg animate-in slide-in-from-top-2">
            <div className="flex items-center gap-3">
              <div className="p-1.5 bg-gray-700 rounded-lg">
                <WifiOff size={16} className="text-red-400" />
              </div>
              <div className="flex flex-col">
                <span className="text-sm font-bold leading-none">Offline Mode Active</span>
                <span className="text-[10px] text-gray-400 font-medium leading-tight">Changes are saved locally and will sync when online.</span>
              </div>
            </div>
            <div className="px-2 py-1 bg-gray-700 rounded text-[10px] font-bold uppercase tracking-wider text-gray-300">
              Local DB Active
            </div>
          </div>
        )}

        {renderContent()}
      </main>

      {/* Floating AI Button (Bottom Right) */}
      <div className="fixed bottom-8 right-8 z-50 print:hidden">
        <button 
           onClick={() => isOnline && setShowAiModal(true)}
           disabled={!isOnline}
           className={`group relative pl-4 pr-6 py-4 rounded-full shadow-[0_8px_30px_rgb(0,0,0,0.12)] transition-all duration-300 flex items-center gap-3 active:scale-95
             ${isOnline 
               ? 'bg-gray-900 hover:bg-gray-800 text-white hover:shadow-[0_8px_30px_rgb(0,0,0,0.2)]' 
               : 'bg-gray-200 text-gray-400 cursor-not-allowed grayscale'
             }`}
        >
          {isOnline && (
            <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></div>
          )}
          <div className={`w-10 h-10 rounded-full flex items-center justify-center shadow-inner ${isOnline ? 'bg-gradient-to-tr from-purple-500 to-indigo-500' : 'bg-gray-300'}`}>
             {isOnline ? <Sparkles size={18} className="text-white fill-white" /> : <WifiOff size={18} className="text-gray-500" />}
          </div>
          <div className="text-left">
             <span className="block text-[10px] font-bold uppercase tracking-wider leading-none mb-0.5">
               {isOnline ? 'AI Consultant' : 'AI Offline'}
             </span>
             <span className="block text-sm font-bold leading-none">
               {isOnline ? 'Ask Gemini' : 'Unavailable'}
             </span>
          </div>
        </button>
      </div>

      {/* AI Modal */}
      {showAiModal && isOnline && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="bg-white w-full max-w-lg rounded-[2rem] shadow-2xl p-0 border border-white/50 overflow-hidden flex flex-col max-h-[80vh]">
             {/* Header */}
             <div className="p-6 bg-gradient-to-r from-gray-900 to-gray-800 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-xl bg-white/10 flex items-center justify-center backdrop-blur-md">
                     <Sparkles size={20} className="text-purple-300" />
                   </div>
                   <div>
                     <h3 className="text-lg font-bold leading-tight">AI Pharmacist</h3>
                     <p className="text-xs text-gray-400 font-medium">Powered by Google Gemini</p>
                   </div>
                </div>
                <button onClick={() => setShowAiModal(false)} className="w-8 h-8 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 transition-colors">✕</button>
             </div>

             {/* Content */}
             <div className="p-6 flex-1 overflow-y-auto bg-gray-50">
               <div className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100 min-h-[200px] mb-4">
                  {aiResponse ? (
                    <div className="prose prose-sm max-w-none text-gray-700 leading-relaxed">
                      {aiResponse.split('\n').map((line, i) => (
                        <p key={i} className="mb-2 last:mb-0">{line}</p>
                      ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400 gap-3 py-10">
                      <MessageSquare size={40} className="opacity-20" />
                      <p className="text-sm font-medium">How can I help you today?</p>
                      <div className="flex flex-wrap justify-center gap-2 mt-2">
                        {['Side effects of Panadol', 'Amoxicillin interactions', 'Insulin storage'].map(s => (
                          <button key={s} onClick={() => setAiQuery(s)} className="text-xs bg-gray-100 px-3 py-1.5 rounded-full hover:bg-gray-200 transition-colors">
                            {s}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}
               </div>

               <p className="text-[10px] text-gray-400 text-center mx-auto max-w-xs leading-relaxed">
                 <span className="font-bold text-gray-500">Disclaimer:</span> AI responses are for informational purposes only and do not replace professional medical advice.
               </p>
             </div>

             {/* Footer Input */}
             <div className="p-4 bg-white border-t border-gray-100">
               <div className="flex gap-2">
                 <input 
                   className="flex-1 bg-gray-100 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-purple-500 outline-none text-sm font-medium transition-all"
                   placeholder="Type your medical query..."
                   value={aiQuery}
                   onChange={(e) => setAiQuery(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && handleAiAsk()}
                   autoFocus
                 />
                 <Button onClick={handleAiAsk} disabled={aiLoading} className="bg-gray-900 hover:bg-black text-white px-6 rounded-xl shadow-lg shadow-gray-900/20">
                   {aiLoading ? (
                     <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                   ) : (
                     <div className="flex items-center gap-2">Ask</div>
                   )}
                 </Button>
               </div>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Medicine } from '../types';
import { clsx } from 'clsx';
import { Pill, Activity } from 'lucide-react';
import { LOW_STOCK_THRESHOLD, formatCurrency } from '../constants';

interface MedicineCardProps {
  medicine: Medicine;
  onClick?: (medicine: Medicine) => void;
  actionSlot?: React.ReactNode; 
}

export const MedicineCard: React.FC<MedicineCardProps> = ({ medicine, onClick, actionSlot }) => {
  const isLowStock = medicine.stock <= LOW_STOCK_THRESHOLD;
  const isOutOfStock = medicine.stock === 0;

  return (
    <div 
      onClick={() => !isOutOfStock && onClick && onClick(medicine)}
      className={clsx(
        "relative flex flex-row items-stretch gap-4 p-4 rounded-2xl transition-all duration-300 group overflow-hidden cursor-pointer",
        "bg-white/90 backdrop-blur-xl border border-white/60",
        "hover:shadow-[0_8px_30px_rgb(0,0,0,0.12)] hover:border-blue-200 hover:scale-[1.01]",
        isOutOfStock 
          ? "opacity-60 grayscale" 
          : "shadow-sm"
      )}
    >
      {/* Left: Icon & visual indicator */}
      <div className="flex flex-col items-center gap-2 shrink-0">
        <div className={clsx(
          "w-14 h-14 rounded-2xl flex items-center justify-center transition-colors duration-300 shadow-sm border border-white",
          isLowStock ? "bg-red-50 text-red-500" : "bg-blue-50 text-blue-600 group-hover:bg-blue-600 group-hover:text-white"
        )}>
          <Pill size={24} strokeWidth={2} />
        </div>

        {/* Status Badge */}
        {isOutOfStock ? (
          <span className="w-full text-center text-[10px] font-bold text-gray-500 bg-gray-100 py-1 rounded-lg uppercase tracking-wider">Out</span>
        ) : isLowStock ? (
          <span className="w-full text-center text-[10px] font-bold text-red-600 bg-red-50 py-1 rounded-lg uppercase tracking-wider animate-pulse border border-red-100">Low</span>
        ) : (
          <span className="w-full text-center text-[10px] font-bold text-emerald-600 bg-emerald-50 py-1 rounded-lg uppercase tracking-wider border border-emerald-100">Ok</span>
        )}
      </div>

      {/* Right: Content */}
      <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
        <div>
           <div className="flex justify-between items-start gap-2">
             <h3 className="font-bold text-gray-900 leading-tight truncate text-base group-hover:text-blue-700 transition-colors">
               {medicine.name}
             </h3>
           </div>

           <p className="text-xs text-gray-500 font-medium truncate flex items-center gap-1 mt-1">
             <Activity size={10} className="text-blue-400" />
             {medicine.genericName}
           </p>
        </div>

        <div className="mt-3 pt-3 border-t border-gray-100 flex items-end justify-between">
           <div className="flex flex-col">
              <span className="text-[9px] font-bold text-gray-400 uppercase tracking-wider mb-0.5">{medicine.unit}</span>
              <span className="text-lg font-black text-gray-900 leading-none tracking-tight">{formatCurrency(medicine.price)}</span>
           </div>

           {actionSlot ? (
              <div className="flex gap-2 ml-2 w-1/2 justify-end" onClick={(e) => e.stopPropagation()}>
                 {actionSlot}
              </div>
           ) : (
              !isOutOfStock && (
                <div className="text-xs font-semibold text-gray-500 bg-gray-50 px-2 py-1 rounded-lg border border-gray-100">
                   Qty: {medicine.stock}
                </div>
              )
           )}
        </div>
      </div>
    </div>
  );
};

