import React, { useEffect, useState, useMemo } from 'react';
import { storageService } from '../services/storageService';
import { Sale, Medicine } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';
import { formatCurrency, LOW_STOCK_THRESHOLD } from '../constants';
import { Calendar, Filter, ChevronRight, Clock, FileText } from 'lucide-react';
import { Button } from '../components/ui/Button';
import { clsx } from 'clsx';

type FilterType = 'daily' | 'weekly' | 'monthly' | 'custom';

const Reports: React.FC = () => {
  const [sales, setSales] = useState<Sale[]>([]);
  const [medicines, setMedicines] = useState<Medicine[]>([]);

  // Filter States
  const [filterType, setFilterType] = useState<FilterType>('weekly');
  const [customDate, setCustomDate] = useState(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    setSales(storageService.getSales());
    setMedicines(storageService.getMedicines());
  }, []);

  // --- Filtering Logic ---
  const filteredSales = useMemo(() => {
    const now = new Date();
    const startOfDay = new Date(now.setHours(0, 0, 0, 0));

    return sales.filter(sale => {
      const saleDate = new Date(sale.date);
      const saleDateStr = sale.date.split('T')[0];

      switch (filterType) {
        case 'daily':
          return saleDateStr === new Date().toISOString().split('T')[0];
        case 'weekly':
          const oneWeekAgo = new Date();
          oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
          return saleDate >= oneWeekAgo;
        case 'monthly':
          const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
          return saleDate >= startOfMonth;
        case 'custom':
          return saleDateStr === customDate;
        default:
          return true;
      }
    });
  }, [sales, filterType, customDate]);

  // --- Chart Data Preparation ---
  const chartData = useMemo(() => {
    if (filterType === 'daily' || filterType === 'custom') {
      // Hourly grouping
      const hours = Array.from({ length: 24 }, (_, i) => ({
        name: `${i.toString().padStart(2, '0')}:00`,
        sales: 0,
        count: 0
      }));

      filteredSales.forEach(sale => {
        const hour = new Date(sale.date).getHours();
        hours[hour].sales += sale.total;
        hours[hour].count += 1;
      });

      // Filter out empty hours from edges for cleaner look, or keep all to show timeline
      return hours;
    } else {
      // Daily grouping (for Weekly/Monthly)
      const daysMap: Record<string, number> = {};

      // Initialize map based on range to ensure continuity
      if (filterType === 'weekly') {
        for(let i=6; i>=0; i--) {
          const d = new Date();
          d.setDate(d.getDate() - i);
          daysMap[d.toLocaleDateString('en-US', { weekday: 'short' })] = 0;
        }
      }

      filteredSales.forEach(sale => {
        const dateKey = new Date(sale.date).toLocaleDateString('en-US', { 
          weekday: filterType === 'weekly' ? 'short' : undefined,
          day: filterType === 'monthly' ? 'numeric' : undefined,
          month: filterType === 'monthly' ? 'short' : undefined,
        });

        // For monthly, key might look like "Oct 1"
        const key = filterType === 'monthly' ? new Date(sale.date).getDate() : dateKey;

        if (filterType === 'monthly') {
             // For monthly, we just map by day number roughly or keep simple
             const dayNum = new Date(sale.date).getDate();
             if (!daysMap[dayNum]) daysMap[dayNum] = 0;
             daysMap[dayNum] += sale.total;
        } else {
             if (daysMap[dateKey] !== undefined) daysMap[dateKey] += sale.total;
             // Handle edge case where initialized map might mismatch slightly due to locale, 
             // but usually safe to just accumulate:
             else daysMap[dateKey] = (daysMap[dateKey] || 0) + sale.total;
        }
      });

      if (filterType === 'monthly') {
          return Object.keys(daysMap).map(k => ({ name: k, sales: daysMap[k] }));
      }

      return Object.keys(daysMap).map(key => ({
        name: key,
        sales: daysMap[key]
      }));
    }
  }, [filteredSales, filterType]);

  // --- Category Data (Based on filtered sales) ---
  const categoryData = useMemo(() => {
    const catMap: Record<string, number> = {};
    filteredSales.forEach(sale => {
      sale.items.forEach(item => {
        if (!catMap[item.category]) catMap[item.category] = 0;
        catMap[item.category] += (item.salePrice * item.quantity);
      });
    });

    return Object.keys(catMap).map(key => ({
      name: key,
      value: catMap[key]
    })).sort((a, b) => b.value - a.value).slice(0, 6);
  }, [filteredSales]);

  // --- KPI Calculations ---
  const totalRevenue = filteredSales.reduce((acc, curr) => acc + curr.total, 0);
  const totalTransactions = filteredSales.length;
  const avgTicket = totalTransactions > 0 ? totalRevenue / totalTransactions : 0;

  // Inventory KPIs (Static, not affected by date filter usually, but good to show context)
  const lowStockCount = medicines.filter(m => m.stock <= LOW_STOCK_THRESHOLD && m.stock > 0).length;

  return (
    <div className="h-full overflow-y-auto pb-10 flex flex-col">

       {/* Header & Controls */}
       <div className="mb-6 flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
         <div>
            <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
              <FileText className="text-medical-blue" /> Sales Reports
            </h2>
            <p className="text-sm text-gray-500 font-medium mt-1">
              Analytics for {filterType === 'custom' ? new Date(customDate).toDateString() : filterType.charAt(0).toUpperCase() + filterType.slice(1) + ' Activity'}
            </p>
         </div>

         <div className="flex flex-wrap items-center gap-2 bg-white p-2 rounded-xl border border-gray-200 shadow-sm">
            <div className="flex gap-1 bg-gray-100 p-1 rounded-lg">
              {(['daily', 'weekly', 'monthly'] as const).map((t) => (
                <button
                  key={t}
                  onClick={() => setFilterType(t)}
                  className={clsx(
                    "px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wider transition-all",
                    filterType === t 
                      ? "bg-white text-medical-blue shadow-sm" 
                      : "text-gray-500 hover:text-gray-700 hover:bg-gray-200/50"
                  )}
                >
                  {t === 'daily' ? 'Today' : t}
                </button>
              ))}
              <button
                onClick={() => setFilterType('custom')}
                className={clsx(
                  "px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wider transition-all",
                  filterType === 'custom' 
                    ? "bg-white text-medical-blue shadow-sm" 
                    : "text-gray-500 hover:text-gray-700 hover:bg-gray-200/50"
                )}
              >
                Date Wise
              </button>
            </div>

            {filterType === 'custom' && (
              <div className="flex items-center gap-2 px-2 border-l border-gray-200">
                <Calendar size={16} className="text-gray-400" />
                <input 
                  type="date" 
                  value={customDate}
                  onChange={(e) => setCustomDate(e.target.value)}
                  className="text-sm font-bold text-gray-700 bg-transparent outline-none cursor-pointer"
                />
              </div>
            )}
         </div>
       </div>

       {/* Metrics Cards */}
       <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Revenue</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{formatCurrency(totalRevenue)}</h3>
           <span className="text-[10px] font-bold text-blue-600 bg-blue-100 px-2 py-1 rounded-full mt-3 inline-block">
             {filterType === 'daily' || filterType === 'custom' ? 'Today\'s Total' : 'Period Total'}
           </span>
         </div>

         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Transactions</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{totalTransactions}</h3>
           <span className="text-[10px] font-bold text-emerald-600 bg-emerald-100 px-2 py-1 rounded-full mt-3 inline-block">
             Orders
           </span>
         </div>

         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Avg. Ticket</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{formatCurrency(Math.round(avgTicket))}</h3>
           <span className="text-[10px] font-bold text-purple-600 bg-purple-100 px-2 py-1 rounded-full mt-3 inline-block">
             Per Sale
           </span>
         </div>

         <div className="glass-panel p-6 rounded-[2rem] border border-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] bg-white/80">
           <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Low Stock SKUs</p>
           <h3 className="text-3xl font-black text-gray-900 tracking-tight">{lowStockCount}</h3>
           <span className="text-[10px] font-bold text-orange-600 bg-orange-100 px-2 py-1 rounded-full mt-3 inline-block">Alerts</span>
         </div>
       </div>

       {/* Charts Row */}
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
         {/* Line Chart */}
         <div className="bg-white/60 backdrop-blur-xl p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-white h-96">
            <h4 className="font-bold text-gray-800 mb-6 text-lg">
              {filterType === 'daily' || filterType === 'custom' ? 'Hourly Activity' : 'Sales Trend'}
            </h4>
            <ResponsiveContainer width="100%" height="100%" className="-ml-4">
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 11, fontWeight: 600}} dy={10} minTickGap={30} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 11, fontWeight: 600}} tickFormatter={(val) => `${val}`} />
                <Tooltip 
                  cursor={{stroke: '#007BFF', strokeWidth: 2, strokeDasharray: '5 5'}}
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)', padding: '12px'}} 
                  itemStyle={{color: '#1F2937', fontWeight: 'bold'}}
                  formatter={(value: number) => [formatCurrency(value), 'Revenue']}
                />
                <Line 
                  type="monotone" 
                  dataKey="sales" 
                  stroke="#007BFF" 
                  strokeWidth={4} 
                  dot={false}
                  activeDot={{r: 8, fill: '#007BFF', stroke: 'white', strokeWidth: 2}} 
                />
              </LineChart>
            </ResponsiveContainer>
         </div>

         {/* Bar Chart */}
         <div className="bg-white/60 backdrop-blur-xl p-8 rounded-[2rem] shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-white h-96">
            <h4 className="font-bold text-gray-800 mb-6 text-lg">Top Categories (Selected Period)</h4>
            {categoryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%" className="-ml-4">
                <BarChart data={categoryData} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#E5E7EB" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{fill: '#6B7280', fontSize: 11, fontWeight: 600}} width={80} />
                  <Tooltip 
                    cursor={{fill: '#F3F4F6', radius: 8}} 
                    contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)', padding: '12px'}}
                    itemStyle={{color: '#1F2937', fontWeight: 'bold'}}
                    formatter={(value: number) => [formatCurrency(value), 'Sales']}
                  />
                  <Bar dataKey="value" fill="#3B82F6" radius={[0, 8, 8, 0]} barSize={24} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400 font-medium">
                No sales data available for this period.
              </div>
            )}
         </div>
       </div>

       {/* Detailed Activity Table */}
       <div className="glass-panel border border-gray-200 rounded-[2rem] overflow-hidden flex flex-col">
         <div className="p-6 border-b border-gray-100 bg-white/50 flex justify-between items-center">
            <h3 className="font-bold text-gray-800 text-lg">Detailed Activity Log</h3>
            <span className="text-xs font-bold text-gray-400 uppercase">{filteredSales.length} Records</span>
         </div>

         <div className="overflow-x-auto">
           <table className="w-full text-left">
             <thead className="bg-gray-50/50">
               <tr className="text-[10px] font-extrabold text-gray-400 uppercase tracking-wider">
                 <th className="p-4">Time / Date</th>
                 <th className="p-4">Invoice ID</th>
                 <th className="p-4">Staff</th>
                 <th className="p-4">Payment</th>
                 <th className="p-4">Items</th>
                 <th className="p-4 text-right">Amount</th>
               </tr>
             </thead>
             <tbody className="divide-y divide-gray-100">
                {filteredSales.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="p-8 text-center text-gray-400 font-medium">
                      No activity found for the selected time range.
                    </td>
                  </tr>
                ) : (
                  filteredSales.slice().reverse().map((sale) => (
                    <tr key={sale.id} className="hover:bg-blue-50/30 transition-colors group">
                       <td className="p-4 text-sm font-medium text-gray-600 flex items-center gap-2">
                          <Clock size={14} className="text-gray-300 group-hover:text-blue-400" />
                          <div>
                            <span className="block text-gray-900 font-bold">{new Date(sale.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                            <span className="text-[10px] text-gray-400">{new Date(sale.date).toLocaleDateString()}</span>
                          </div>
                       </td>
                       <td className="p-4 text-sm font-mono text-gray-500">#{sale.id.slice(-6)}</td>
                       <td className="p-4 text-sm text-gray-700 font-medium">{sale.staffName}</td>
                       <td className="p-4">
                         <span className={clsx(
                           "text-[9px] font-bold uppercase tracking-wider px-2 py-1 rounded-md border",
                           sale.paymentMethod === 'Cash' ? "bg-green-50 text-green-700 border-green-100" :
                           sale.paymentMethod === 'Card' ? "bg-purple-50 text-purple-700 border-purple-100" :
                           "bg-blue-50 text-blue-700 border-blue-100"
                         )}>
                           {sale.paymentMethod}
                         </span>
                       </td>
                       <td className="p-4 text-sm text-gray-600">
                         {sale.items.map(i => i.name).join(', ').slice(0, 30)}{sale.items.length > 1 ? '...' : ''}
                         <span className="text-xs text-gray-400 ml-1">({sale.items.length} items)</span>
                       </td>
                       <td className="p-4 text-right text-sm font-black text-gray-900">
                         {formatCurrency(sale.total)}
                       </td>
                    </tr>
                  ))
                )}
             </tbody>
           </table>
         </div>
       </div>

    </div>
  );
};

export default Reports;

export interface Medicine {
  id: string;
  name: string;
  genericName: string; // Salt
  category: string;
  price: number;
  stock: number;
  expiryDate: string;
  batchNumber: string;
  unit: 'Tablet' | 'Strip' | 'Bottle' | 'Box' | 'Injection' | 'Inhaler' | 'Tube';
}

export interface CartItem extends Medicine {
  quantity: number;
  saleUnit: string;     // The unit being sold (e.g. 'Box')
  salePrice: number;    // The price of the unit being sold
  skuDeduction: number; // Stock deduction factor (e.g. 10 if selling Box when SKU is Strip)
}

export interface Sale {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  staffName: string;
  paymentMethod: 'Cash' | 'Card' | 'UPI';
  customerName?: string;
  customerPhone?: string;
}

export interface StockEntry {
  id: string;
  date: string;
  medicineId: string;
  medicineName: string;
  quantity: number;
  type: 'IN' | 'OUT';
  reason: string; // e.g., 'New Batch', 'Expired', 'Damaged'
  batchNumber?: string;
  supplier?: string;
}

export interface Patient {
  id: string;
  name: string;
  phone: string;
  age?: number;
  gender?: 'Male' | 'Female' | 'Other';
  chronicConditions?: string;
  history: string[]; // Array of sale IDs
}

export interface Supplier {
  id: string;
  name: string;
  contact: string;
  email?: string;
  medicinesSupplied: string[];
}

export interface User {
  username: string;
  role: 'admin' | 'staff';
  permissions: {
    inventory: boolean;
    stock: boolean;
    suppliers: boolean;
    settings: boolean;
  };
}

export enum Tab {
  COUNTER = 'COUNTER',
  INVENTORY = 'INVENTORY',
  STOCK = 'STOCK',
  PATIENTS = 'PATIENTS',
  SUPPLIERS = 'SUPPLIERS',
  REPORTS = 'REPORTS',
  SETTINGS = 'SETTINGS'
}

import React, { useState, useEffect, useMemo } from 'react';
import { Search, ShoppingCart, Trash2, Plus, Minus, CreditCard, Banknote, FileText, X, ChevronRight, Package2, User, Phone } from 'lucide-react';
import { Medicine, CartItem, Sale } from '../types';
import { MedicineCard } from '../components/MedicineCard';
import { Button } from '../components/ui/Button';
import { InvoiceModal } from '../components/InvoiceModal';
import { storageService } from '../services/storageService';
import { CURRENCY, CATEGORIES, UNITS, formatCurrency } from '../constants';
import { clsx } from 'clsx';

const Counter: React.FC = () => {
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedUnit, setSelectedUnit] = useState('All');

  const [cart, setCart] = useState<CartItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<'Cash' | 'Card' | 'UPI'>('Cash');
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');

  const [lastSale, setLastSale] = useState<Sale | null>(null);
  const [showInvoice, setShowInvoice] = useState(false);

  // Unit Selection Modal State
  const [selectedMedForUnit, setSelectedMedForUnit] = useState<Medicine | null>(null);

  // Load initial data
  const loadData = () => {
    setMedicines(storageService.getMedicines());
  };

  useEffect(() => {
    loadData();
  }, []);

  const filteredMedicines = useMemo(() => {
    const term = search.toLowerCase();
    const today = new Date();
    today.setHours(0,0,0,0);

    return medicines.filter(m => {
      // 1. Expiry Check - Hide Expired Items
      const expiry = new Date(m.expiryDate);
      if (expiry < today) return false; 

      // 2. Search
      const matchesSearch = 
        m.name.toLowerCase().includes(term) || 
        m.genericName.toLowerCase().includes(term);

      // 3. Filters
      const matchesCategory = selectedCategory === 'All' || m.category === selectedCategory;
      const matchesUnit = selectedUnit === 'All' || m.unit === selectedUnit;

      return matchesSearch && matchesCategory && matchesUnit;
    });
  }, [medicines, search, selectedCategory, selectedUnit]);

  // Conversion Logic
  const getConversionOptions = (med: Medicine) => {
    const options = [];
    options.push({ unit: med.unit, price: med.price, factor: 1, label: `Base (${med.unit})` });

    if (med.unit === 'Box') {
      options.push({ unit: 'Strip', price: med.price / 10, factor: 0.1, label: 'Loose Strip (1/10 Box)' });
      options.push({ unit: 'Tablet', price: med.price / 100, factor: 0.01, label: 'Loose Tablet (1/100 Box)' });
    } else if (med.unit === 'Strip') {
      options.push({ unit: 'Box', price: med.price * 10, factor: 10, label: 'Full Box (10 Strips)' });
      options.push({ unit: 'Tablet', price: med.price / 10, factor: 0.1, label: 'Loose Tablet (1/10 Strip)' });
    } else if (med.unit === 'Tablet') {
      options.push({ unit: 'Strip', price: med.price * 10, factor: 10, label: 'Full Strip (10 Tabs)' });
      options.push({ unit: 'Box', price: med.price * 100, factor: 100, label: 'Full Box (100 Tabs)' });
    }

    return options;
  };

  const handleMedicineClick = (medicine: Medicine) => {
    if (['Box', 'Strip', 'Tablet'].includes(medicine.unit)) {
      setSelectedMedForUnit(medicine);
    } else {
      addToCart(medicine, medicine.unit, medicine.price, 1);
    }
  };

  const addToCart = (medicine: Medicine, saleUnit: string, salePrice: number, skuDeduction: number) => {
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.id === medicine.id && item.saleUnit === saleUnit);

      if (existingIndex >= 0) {
        const existingItem = prev[existingIndex];
        const totalSkuRequired = (existingItem.quantity + 1) * skuDeduction;
        if (totalSkuRequired > medicine.stock) {
            alert(`Insufficient stock! You have ${medicine.stock} ${medicine.unit}(s).`);
            return prev;
        }

        const newCart = [...prev];
        newCart[existingIndex] = { ...existingItem, quantity: existingItem.quantity + 1 };
        return newCart;
      }

      if (skuDeduction > medicine.stock) {
         alert(`Insufficient stock! You need ${skuDeduction} ${medicine.unit}(s) but only have ${medicine.stock}.`);
         return prev;
      }

      return [...prev, { 
        ...medicine, 
        quantity: 1,
        saleUnit,
        salePrice,
        skuDeduction
      }];
    });
    setSelectedMedForUnit(null);
  };

  const removeFromCart = (index: number) => {
    setCart(prev => prev.filter((_, i) => i !== index));
  };

  const updateQuantity = (index: number, newQty: number) => {
    if (newQty < 0) return; // Prevent negative inputs

    setCart(prev => {
      return prev.map((item, i) => {
        if (i === index) {
          if (newQty === 0) return item; 

          // Check stock
          const med = medicines.find(m => m.id === item.id);
          if (med) {
            const requiredStock = newQty * item.skuDeduction;
            if (requiredStock > med.stock) {
                return item;
            }
          }
          return { ...item, quantity: newQty };
        }
        return item;
      });
    });
  };

  const subtotal = cart.reduce((sum, item) => sum + (item.salePrice * item.quantity), 0);
  const total = subtotal;

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const sale: Sale = {
      id: Math.floor(Math.random() * 900000 + 100000).toString(),
      date: new Date().toISOString(),
      items: cart,
      total: total,
      staffName: 'Staff',
      paymentMethod,
      customerName: customerName || 'Walk-in Customer',
      customerPhone: customerPhone || 'N/A'
    };

    // The Service now handles:
    // 1. Saving Sale
    // 2. Decrementing Stock
    // 3. Creating "Sale" log in Stock History
    storageService.addSale(sale);

    // Refresh local state to reflect new stock levels
    loadData();

    setCart([]);
    setCustomerName('');
    setCustomerPhone('');
    setLastSale(sale);
    setShowInvoice(true);
  };

  return (
    <>
      <div className="flex h-full gap-6">
        {/* Left: Medicine Grid */}
        <div className="flex-1 flex flex-col h-full overflow-hidden">
          {/* Controls */}
          <div className="mb-6 flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input 
                type="text" 
                placeholder="Search Brand or Salt..." 
                className="w-full pl-12 pr-4 py-3.5 rounded-2xl border-none bg-white shadow-sm focus:ring-2 focus:ring-blue-100 outline-none text-base text-gray-700"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                autoFocus
              />
            </div>

            <div className="flex gap-2">
               <select 
                 className="px-4 py-3 rounded-2xl border-none bg-white shadow-sm text-gray-600 text-sm focus:ring-2 focus:ring-blue-100 outline-none cursor-pointer"
                 value={selectedCategory}
                 onChange={(e) => setSelectedCategory(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
               </select>

               <select 
                 className="px-4 py-3 rounded-2xl border-none bg-white shadow-sm text-gray-600 text-sm focus:ring-2 focus:ring-blue-100 outline-none cursor-pointer"
                 value={selectedUnit}
                 onChange={(e) => setSelectedUnit(e.target.value)}
               >
                 <option value="All">All Units</option>
                 {UNITS.map(u => <option key={u} value={u}>{u}</option>)}
               </select>
            </div>
          </div>

          {/* Grid */}
          <div className="flex-1 overflow-y-auto pr-2 pb-20">
            {/* Horizontal Grid Layout Adjustment */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4 gap-4 p-1">
              {filteredMedicines.map(med => (
                <MedicineCard key={med.id} medicine={med} onClick={handleMedicineClick} />
              ))}
            </div>
            {filteredMedicines.length === 0 && (
               <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                 <Package2 size={48} className="mb-4 opacity-50" />
                 <p className="font-medium">No medicines found.</p>
                 <p className="text-xs mt-2 opacity-70">(Expired items are hidden)</p>
               </div>
            )}
          </div>
        </div>

        {/* Right: Cart */}
        <div className="w-96 glass-panel rounded-[2rem] flex flex-col border border-white/60 shadow-xl overflow-hidden bg-white/80 backdrop-blur-2xl">
          <div className="p-6 border-b border-gray-100 bg-white/40">
            <div className="flex items-center justify-between">
              <h2 className="font-extrabold text-gray-800 text-lg flex items-center gap-2">
                <ShoppingCart className="text-medical-blue fill-current" size={20} /> Current Sale
              </h2>
              <span className="bg-blue-600 text-white text-xs font-bold px-2.5 py-1 rounded-full shadow-lg shadow-blue-500/30">
                {cart.length}
              </span>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                <ShoppingCart size={48} className="mb-3" />
                <p>Cart is empty</p>
              </div>
            ) : (
              cart.map((item, idx) => (
                <div key={`${item.id}-${item.saleUnit}`} className="bg-white p-4 rounded-2xl border border-gray-50 shadow-[0_4px_20px_rgb(0,0,0,0.03)] flex flex-col gap-3 group transition-all hover:scale-[1.01]">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-bold text-gray-800 text-sm leading-tight">{item.name}</h4>
                      <p className="text-[10px] text-gray-500 font-medium">{item.genericName}</p>
                    </div>
                    <button onClick={() => removeFromCart(idx)} className="text-gray-300 hover:text-red-500 transition-colors p-1">
                       <Trash2 size={16} />
                    </button>
                  </div>

                  <div className="flex items-center justify-between">
                     <div className="flex items-center gap-2">
                        <span className="text-[10px] font-bold text-gray-500 bg-gray-100 px-2 py-1 rounded-md uppercase tracking-wider">{item.saleUnit}</span>
                        <div className="flex items-center bg-gray-50 rounded-xl p-0.5 border border-gray-200">
                           <button onClick={() => updateQuantity(idx, item.quantity - 1)} className="w-7 h-7 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-600"><Minus size={12} /></button>
                           <input 
                             type="number"
                             min="1"
                             className="w-10 text-center bg-transparent text-sm font-bold text-gray-800 outline-none p-0 border-none focus:ring-0"
                             value={item.quantity}
                             onChange={(e) => {
                               const val = parseInt(e.target.value);
                               if (!isNaN(val)) updateQuantity(idx, val);
                             }}
                           />
                           <button onClick={() => updateQuantity(idx, item.quantity + 1)} className="w-7 h-7 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-600"><Plus size={12} /></button>
                        </div>
                     </div>
                     <span className="text-base font-bold text-medical-blue">{formatCurrency(item.salePrice * item.quantity)}</span>
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="p-6 bg-white border-t border-gray-100">
             {/* Customer Details Inputs */}
             <div className="grid grid-cols-2 gap-3 mb-4">
                <div className="relative">
                   <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-3 h-3" />
                   <input 
                     type="text" 
                     placeholder="Customer Name"
                     className="w-full pl-8 pr-3 py-2 rounded-xl bg-gray-50 border border-gray-200 text-xs font-semibold outline-none focus:ring-1 focus:ring-blue-500"
                     value={customerName}
                     onChange={(e) => setCustomerName(e.target.value)}
                   />
                </div>
                <div className="relative">
                   <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-3 h-3" />
                   <input 
                     type="text" 
                     placeholder="Mobile No."
                     className="w-full pl-8 pr-3 py-2 rounded-xl bg-gray-50 border border-gray-200 text-xs font-semibold outline-none focus:ring-1 focus:ring-blue-500"
                     value={customerPhone}
                     onChange={(e) => setCustomerPhone(e.target.value)}
                   />
                </div>
             </div>

            <div className="space-y-1 mb-6">
              <div className="flex justify-between text-xs text-gray-500 font-medium">
                <span>Subtotal</span>
                <span>{formatCurrency(subtotal)}</span>
              </div>
              <div className="flex justify-between text-2xl font-black text-gray-900">
                <span>Total</span>
                <span>{formatCurrency(total)}</span>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2 mb-6">
              {['Cash', 'Card', 'UPI'].map((method) => (
                <button
                  key={method}
                  onClick={() => setPaymentMethod(method as any)}
                  className={clsx(
                    "py-2.5 rounded-xl text-[10px] font-bold border transition-all flex flex-col items-center gap-1 uppercase tracking-wide",
                    paymentMethod === method 
                      ? "bg-gray-900 text-white border-gray-900 shadow-lg" 
                      : "bg-white text-gray-500 border-gray-100 hover:border-gray-300 hover:bg-gray-50"
                  )}
                >
                  {method === 'Cash' && <Banknote size={16} />}
                  {method === 'Card' && <CreditCard size={16} />}
                  {method === 'UPI' && <FileText size={16} />}
                  {method}
                </button>
              ))}
            </div>

            <Button 
              className="w-full py-4 text-base font-bold rounded-xl shadow-[0_10px_20px_-5px_rgba(37,99,235,0.4)] bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-700 hover:to-blue-600 transform active:scale-[0.98] transition-all" 
              onClick={handleCheckout}
              disabled={cart.length === 0}
            >
              Confirm & Print Receipt
            </Button>
          </div>
        </div>
      </div>

      {showInvoice && lastSale && (
        <InvoiceModal 
          sale={lastSale} 
          onClose={() => setShowInvoice(false)} 
        />
      )}

      {/* Unit Selection Modal */}
      {selectedMedForUnit && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-md p-4 animate-in fade-in zoom-in duration-200">
           <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-sm overflow-hidden border border-white/50">
             <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                <h3 className="font-bold text-gray-900 text-lg">Select Unit</h3>
                <button onClick={() => setSelectedMedForUnit(null)} className="p-1 hover:bg-gray-200 rounded-full transition-colors"><X size={20} className="text-gray-500"/></button>
             </div>
             <div className="p-5 bg-white/80">
               <div className="mb-6 text-center">
                 <h4 className="font-black text-xl text-gray-800">{selectedMedForUnit.name}</h4>
                 <div className="inline-block mt-2 px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-xs font-bold">
                   Available: {selectedMedForUnit.stock} {selectedMedForUnit.unit}s
                 </div>
               </div>
               <div className="space-y-3">
                 {getConversionOptions(selectedMedForUnit).map((opt) => (
                   <button 
                     key={opt.unit}
                     onClick={() => addToCart(selectedMedForUnit, opt.unit, opt.price, opt.factor)}
                     className="w-full flex items-center justify-between p-4 rounded-2xl border border-gray-100 bg-white hover:border-blue-500 hover:shadow-lg hover:shadow-blue-500/10 transition-all group"
                   >
                     <div className="text-left">
                       <span className="block font-bold text-gray-800 text-sm group-hover:text-blue-600 transition-colors">{opt.label}</span>
                       <span className="text-[10px] text-gray-400 font-semibold uppercase tracking-wider">Sell as {opt.unit}</span>
                     </div>
                     <div className="flex items-center gap-3">
                       <span className="font-bold text-gray-900 text-lg">{formatCurrency(opt.price)}</span>
                       <ChevronRight size={18} className="text-gray-300 group-hover:text-blue-500" />
                     </div>
                   </button>
                 ))}
               </div>
             </div>
           </div>
        </div>
      )}
    </>
  );
};

export default Counter;

import React from 'react';
import { X, Printer, Download } from 'lucide-react';
import { Sale } from '../types';
import { formatCurrency } from '../constants';
import { Button } from './ui/Button';

interface InvoiceModalProps {
  sale: Sale | null;
  onClose: () => void;
}

export const InvoiceModal: React.FC<InvoiceModalProps> = ({ sale, onClose }) => {
  if (!sale) return null;

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadPDF = () => {
    // @ts-ignore
    if (typeof window.html2pdf === 'undefined') {
      alert("PDF Generator is loading. Please try again in a moment.");
      return;
    }

    const element = document.getElementById('printable-invoice');
    const opt = {
      margin: 0,
      filename: `${sale.customerName?.replace(/\s+/g, '_') || 'Customer'}_${sale.id}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      // 80mm width, height auto approx 200-300mm depending on length
      jsPDF: { unit: 'mm', format: [80, 297], orientation: 'portrait' } 
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(element).save();
  };

  return (
    <div id="invoice-modal-overlay" className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm print:bg-white print:p-0 print:block print:static print:inset-auto print:h-auto">
      {/* 
         Thermal Printer Layout Spec:
         - Width: ~300px-320px (80mm) to match standard receipt printers
         - Font: Monospace/Sans for clarity and retro receipt look
      */}
      <div id="printable-invoice" className="bg-white rounded-xl shadow-2xl w-full max-w-[320px] overflow-hidden flex flex-col max-h-[90vh] print:shadow-none print:max-w-none print:w-full print:rounded-none print:h-auto print:overflow-visible print:block">

        {/* Header (Hidden in Print) */}
        <div className="p-3 border-b border-gray-100 flex justify-between items-center bg-gray-50 print:hidden" data-html2canvas-ignore="true">
          <h3 className="font-bold text-gray-800 text-sm">Receipt Preview</h3>
          <button 
            onClick={onClose} 
            className="text-gray-400 hover:text-gray-600 p-1 hover:bg-gray-200 rounded-full transition-colors"
            aria-label="Close Receipt"
          >
            <X size={18} />
          </button>
        </div>

        {/* Invoice Content - Thermal Optimized */}
        <div className="p-4 overflow-y-auto flex-1 bg-white print:p-0 print:overflow-visible print:h-auto font-mono text-sm leading-tight text-black">
          <div className="text-center mb-4">
            <h1 className="text-xl font-black text-black uppercase tracking-widest mb-1">Pharma-Core</h1>
            <p className="text-[10px] text-gray-600 font-bold uppercase">Medical Store</p>
            <p className="text-[10px] text-gray-500 mt-1">123 Health Ave, Med City</p>
            <p className="text-[10px] text-gray-500">Tel: +92 300 1234567</p>

            <div className="w-full border-b border-dashed border-gray-400 my-3"></div>

            <div className="flex justify-between text-[10px] font-bold text-gray-700">
              <span>{new Date(sale.date).toLocaleDateString()} {new Date(sale.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
              <span>#{sale.id.slice(-6)}</span>
            </div>
            <div className="flex justify-between text-[10px] font-bold text-gray-700 mt-1">
               <span>Staff: {sale.staffName}</span>
               <span>Pay: {sale.paymentMethod}</span>
            </div>

            {/* Customer Details */}
            {(sale.customerName || sale.customerPhone) && (
              <div className="mt-2 text-left border border-gray-300 rounded p-1">
                {sale.customerName && <p className="text-[10px] font-bold truncate">Cust: {sale.customerName}</p>}
                {sale.customerPhone && <p className="text-[10px] text-gray-600">Ph: {sale.customerPhone}</p>}
              </div>
            )}

            <div className="w-full border-b border-dashed border-gray-400 my-3"></div>
          </div>

          <div className="mb-4">
             {/* Thermal Table Layout: Item Name on top, Qty x Price = Total below */}
             <div className="flex flex-col gap-3">
                {sale.items.map((item, idx) => (
                  <div key={idx} className="flex flex-col">
                    <span className="font-bold text-black text-xs uppercase">{item.name}</span>
                    <span className="font-normal text-[10px] text-gray-500 -mt-0.5 mb-0.5">{item.genericName}</span>
                    <div className="flex justify-between items-center text-[10px] text-gray-800 pl-2">
                       <span>{item.quantity} x {item.salePrice} ({item.saleUnit})</span>
                       <span className="font-bold text-black">{formatCurrency(item.salePrice * item.quantity)}</span>
                    </div>
                  </div>
                ))}
             </div>
          </div>

          <div className="w-full border-b border-dashed border-gray-400 my-3"></div>

          <div className="space-y-1">
            <div className="flex justify-between font-bold text-base text-black">
              <span>TOTAL</span>
              <span>{formatCurrency(sale.total)}</span>
            </div>
            <div className="flex justify-between text-[10px] font-medium text-gray-600">
              <span>Items Count</span>
              <span>{sale.items.length}</span>
            </div>
          </div>

          <div className="mt-6 text-center space-y-1">
            <p className="text-[10px] font-bold text-black uppercase">No Return / Exchange</p>
            <p className="text-[10px] text-gray-600">Thank you for your visit!</p>
            <div className="mt-2 text-[9px] text-gray-400 font-mono">
                System: Pharma-Core POS
            </div>
            {/* Cut Line for Printer */}
            <div className="print:block hidden pt-4 text-center text-[10px] text-gray-400">
               . . . . . . . . . . . . . . . . . . .
            </div>
          </div>
        </div>

        {/* Footer Actions (Hidden in Print) */}
        <div className="p-3 border-t border-gray-100 bg-gray-50 flex flex-col gap-2 print:hidden" data-html2canvas-ignore="true">
           <div className="flex gap-2">
             <Button variant="secondary" size="sm" onClick={onClose} className="flex-1">Close</Button>
             <Button size="sm" onClick={handleDownloadPDF} className="flex-1 gap-2 bg-purple-600 hover:bg-purple-700 text-white">
               <Download size={16} /> PDF
             </Button>
           </div>
           <Button size="sm" onClick={handlePrint} className="w-full gap-2 bg-gray-900 hover:bg-black text-white">
             <Printer size={16} /> Print Receipt
           </Button>
        </div>
      </div>

      {/* Print Specific Styles */}
      <style>{`
        @media print {
          @page {
            size: 80mm auto; /* 80mm width for thermal paper */
            margin: 0;
          }

          body {
            background: white !important;
          }

          /* Hide everything first */
          body * {
            visibility: hidden;
            height: 0; 
            overflow: hidden;
          }

          /* Only show the modal overlay and its children */
          #invoice-modal-overlay, #invoice-modal-overlay * {
            visibility: visible;
            height: auto;
            overflow: visible;
          }

          #invoice-modal-overlay {
            position: absolute !important;
            left: 0 !important;
            top: 0 !important;
            width: 100% !important;
            margin: 0 !important;
            padding: 0 !important;
            background: white !important;
            z-index: 9999 !important;
            display: block !important;
          }

          #printable-invoice {
            width: 76mm !important; /* Slightly less than 80mm to allow for hardware margins */
            max-width: 76mm !important;
            box-shadow: none !important;
            border: none !important;
            border-radius: 0 !important;
            padding: 0 !important;
            margin: 0 !important;
            position: absolute !important;
            top: 0 !important;
            left: 0 !important;
          }

          /* Force standard colors and fonts for thermal printers */
          * {
            -webkit-print-color-adjust: exact !important;
            color-adjust: exact !important;
            font-family: 'Courier New', Courier, monospace !important; /* Monospace for receipts */
          }

          .print\\:hidden {
            display: none !important;
          }

          .print\\:block {
             display: block !important;
          }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Tab, User } from './types';
import Login from './pages/Login';
import Counter from './pages/Counter';
import Inventory from './pages/Inventory';
import Reports from './pages/Reports';
import Stock from './pages/Stock';
import Patients from './pages/Patients';
import Suppliers from './pages/Suppliers';
import Settings from './pages/Settings';
import { MessageSquare, Sparkles, WifiOff, Wifi, ChevronLeft, ChevronRight } from 'lucide-react';
import { getDrugInfo } from './services/geminiService';
import { Button } from './components/ui/Button';

const App: React.FC = () => {
  // Initialize with Admin user to make Login window inactive (bypass it)
  const [user, setUser] = useState<User | null>({
    username: 'admin',
    role: 'admin',
    permissions: { 
      inventory: true, 
      stock: true, 
      suppliers: true, 
      settings: true 
    }
  });

  const [activeTab, setActiveTab] = useState<Tab>(Tab.COUNTER);
  const [showAiModal, setShowAiModal] = useState(false);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [aiLoading, setAiLoading] = useState(false);

  // AI Button Toggle State
  const [isAiButtonVisible, setIsAiButtonVisible] = useState(true);

  // Offline Mode State
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  const handleAiAsk = async () => {
    if (!aiQuery || !isOnline) return;
    setAiLoading(true);
    setAiResponse('');
    const res = await getDrugInfo(aiQuery, 'general');
    setAiResponse(res);
    setAiLoading(false);
  }

  const renderContent = () => {
    switch (activeTab) {
      case Tab.COUNTER:
        return <Counter />;
      case Tab.INVENTORY:
        return <Inventory />;
      case Tab.STOCK:
        return <Stock />;
      case Tab.PATIENTS:
        return <Patients />;
      case Tab.SUPPLIERS:
        return <Suppliers />;
      case Tab.REPORTS:
        return <Reports />;
      case Tab.SETTINGS:
        return <Settings />;
      default:
        return <Counter />;
    }
  };

  return (
    <div className="flex h-screen bg-[#F0F2F5] text-gray-900 font-sans overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={setActiveTab} 
        user={user} 
        onLogout={() => setUser(null)} 
      />

      <main className="flex-1 ml-64 p-6 h-full overflow-hidden relative flex flex-col">
        {/* Offline Banner */}
        {!isOnline && (
          <div className="mb-4 bg-gray-800 text-white px-4 py-2 rounded-xl flex items-center justify-between shadow-lg animate-in slide-in-from-top-2">
            <div className="flex items-center gap-3">
              <div className="p-1.5 bg-gray-700 rounded-lg">
                <WifiOff size={16} className="text-red-400" />
              </div>
              <div className="flex flex-col">
                <span className="text-sm font-bold leading-none">Offline Mode Active</span>
                <span className="text-[10px] text-gray-400 font-medium leading-tight">Changes are saved locally and will sync when online.</span>
              </div>
            </div>
            <div className="px-2 py-1 bg-gray-700 rounded text-[10px] font-bold uppercase tracking-wider text-gray-300">
              Local DB Active
            </div>
          </div>
        )}

        {renderContent()}
      </main>

      {/* Floating AI Button (Right Middle) */}
      <div className="fixed right-0 top-1/2 -translate-y-1/2 z-50 print:hidden flex items-center">
        {/* Toggle Tab */}
        <button 
          onClick={() => setIsAiButtonVisible(!isAiButtonVisible)}
          className="bg-gray-900 text-white py-3 px-1 rounded-l-lg shadow-lg hover:bg-gray-800 transition-colors"
          title={isAiButtonVisible ? "Hide AI" : "Show AI"}
        >
          {isAiButtonVisible ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
        </button>

        {/* The Button Panel */}
        <div className={`transition-all duration-300 transform ${isAiButtonVisible ? 'translate-x-0' : 'translate-x-full'}`}>
           <button 
              onClick={() => isOnline && setShowAiModal(true)}
              disabled={!isOnline}
              className={`group flex flex-col items-center justify-center p-4 gap-2 shadow-[0_8px_30px_rgb(0,0,0,0.12)] active:scale-95 border-l border-white/20
                ${isOnline 
                  ? 'bg-gray-900 hover:bg-gray-800 text-white w-24 rounded-l-xl' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed grayscale w-24 rounded-l-xl'
                }`}
           >
             {isOnline && (
               <div className="absolute top-3 right-3 w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
             )}
             <div className={`w-10 h-10 rounded-full flex items-center justify-center shadow-inner ${isOnline ? 'bg-gradient-to-tr from-purple-500 to-indigo-500' : 'bg-gray-300'}`}>
                {isOnline ? <Sparkles size={18} className="text-white fill-white" /> : <WifiOff size={18} className="text-gray-500" />}
             </div>
             <div className="text-center">
                <span className="block text-[9px] font-bold uppercase tracking-wider leading-none mb-1">
                  AI Help
                </span>
                <span className="block text-xs font-bold leading-none">
                  Consult
                </span>
             </div>
           </button>
        </div>
      </div>

      {/* AI Modal */}
      {showAiModal && isOnline && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="bg-white w-full max-w-lg rounded-[2rem] shadow-2xl p-0 border border-white/50 overflow-hidden flex flex-col max-h-[80vh]">
             {/* Header */}
             <div className="p-6 bg-gradient-to-r from-gray-900 to-gray-800 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-xl bg-white/10 flex items-center justify-center backdrop-blur-md">
                     <Sparkles size={20} className="text-purple-300" />
                   </div>
                   <div>
                     <h3 className="text-lg font-bold leading-tight">AI Pharmacist</h3>
                     <p className="text-xs text-gray-400 font-medium">Powered by Google Gemini</p>
                   </div>
                </div>
                <button onClick={() => setShowAiModal(false)} className="w-8 h-8 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 transition-colors">✕</button>
             </div>

             {/* Content */}
             <div className="p-6 flex-1 overflow-y-auto bg-gray-50">
               <div className="bg-white rounded-2xl p-5 shadow-sm border border-gray-100 min-h-[200px] mb-4">
                  {aiResponse ? (
                    <div className="prose prose-sm max-w-none text-gray-700 leading-relaxed">
                      {aiResponse.split('\n').map((line, i) => (
                        <p key={i} className="mb-2 last:mb-0">{line}</p>
                      ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400 gap-3 py-10">
                      <MessageSquare size={40} className="opacity-20" />
                      <p className="text-sm font-medium">How can I help you today?</p>
                      <div className="flex flex-wrap justify-center gap-2 mt-2">
                        {['Side effects of Panadol', 'Amoxicillin interactions', 'Insulin storage'].map(s => (
                          <button key={s} onClick={() => setAiQuery(s)} className="text-xs bg-gray-100 px-3 py-1.5 rounded-full hover:bg-gray-200 transition-colors">
                            {s}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}
               </div>

               <p className="text-[10px] text-gray-400 text-center mx-auto max-w-xs leading-relaxed">
                 <span className="font-bold text-gray-500">Disclaimer:</span> AI responses are for informational purposes only and do not replace professional medical advice.
               </p>
             </div>

             {/* Footer Input */}
             <div className="p-4 bg-white border-t border-gray-100">
               <div className="flex gap-2">
                 <input 
                   className="flex-1 bg-gray-100 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-purple-500 outline-none text-sm font-medium transition-all"
                   placeholder="Type your medical query..."
                   value={aiQuery}
                   onChange={(e) => setAiQuery(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && handleAiAsk()}
                   autoFocus
                 />
                 <Button onClick={handleAiAsk} disabled={aiLoading} className="bg-gray-900 hover:bg-black text-white px-6 rounded-xl shadow-lg shadow-gray-900/20">
                   {aiLoading ? (
                     <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                   ) : (
                     <div className="flex items-center gap-2">Ask</div>
                   )}
                 </Button>
               </div>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

