             {/* Header */}
             <div className="p-6 bg-gradient-to-r from-gray-900 to-gray-800 flex justify-between items-center text-white">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-xl bg-white/10 flex items-center justify-center backdrop-blur-md">
                     <Sparkles size={20} className="text-purple-300" />
                   </div>
                   <div>
                     <h3 className="text-lg font-bold leading-tight">AI Pharmacist</h3>
                     <p className="text-xs text-gray-400 font-medium">Powered by Google Gemini</p>
