import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Tab, User } from './types';
import Login from './pages/Login';
import Counter from './pages/Counter';
import Inventory from './pages/Inventory';
import Reports from './pages/Reports';
import Stock from './pages/Stock';
import Suppliers from './pages/Suppliers';
import Settings from './pages/Settings';
import { WifiOff, Stethoscope, LogOut } from 'lucide-react';
import { clsx } from 'clsx';

const App: React.FC = () => {
  // Initialize with Admin user to make Login window inactive (bypass it)
  const [user, setUser] = useState<User | null>({
    username: 'admin',
    role: 'admin',
    permissions: { 
      inventory: true, 
      stock: true, 
      suppliers: true, 
      settings: true 
    }
  });

  const [activeTab, setActiveTab] = useState<Tab>(Tab.COUNTER);

  // Offline Mode State
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case Tab.COUNTER:
        return <Counter />;
      case Tab.INVENTORY:
        return <Inventory />;
      case Tab.STOCK:
        return <Stock />;
      case Tab.SUPPLIERS:
        return <Suppliers />;
      case Tab.REPORTS:
        return <Reports />;
      case Tab.SETTINGS:
        return <Settings />;
      default:
        return <Counter />;
    }
  };

  return (
    <div className="flex flex-col md:flex-row h-screen bg-[#F0F2F5] text-gray-900 font-sans overflow-hidden">

      {/* Mobile Top Header (Visible only on Mobile) */}
      <header className="md:hidden flex items-center justify-between p-4 bg-white/80 backdrop-blur-md border-b border-gray-200 fixed top-0 left-0 w-full z-30 h-16">
