      */}
      <main className="flex-1 md:ml-20 lg:ml-20 p-4 pt-20 pb-24 md:p-6 md:pb-6 h-full overflow-hidden relative flex flex-col transition-all duration-300">
        {/* Offline Banner */}
        {!isOnline && (
          <div className="mb-4 bg-gray-800 text-white px-4 py-2 rounded-xl flex items-center justify-between shadow-lg animate-in slide-in-from-top-2">
            <div className="flex items-center gap-3">
