import React, { useEffect, useState } from 'react';
import { 
  Store, 
  Package, 
  Truck, 
  Users, 
  Contact, 
  BarChart3, 
  Settings, 
  LogOut,
  Stethoscope,
} from 'lucide-react';
import { Tab, User } from '../types';
import { clsx } from 'clsx';
import { storageService } from '../services/storageService';
import { LOW_STOCK_THRESHOLD, EXPIRY_WARNING_DAYS } from '../constants';

interface SidebarProps {
  activeTab: Tab;
  onTabChange: (tab: Tab) => void;
  user: User;
  onLogout: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ activeTab, onTabChange, user, onLogout }) => {
  const [lowStockCount, setLowStockCount] = useState(0);
  const [expiringCount, setExpiringCount] = useState(0);

  // Fetch alert data on mount and whenever activeTab changes (to refresh after edits/sales)
  useEffect(() => {
    const medicines = storageService.getMedicines();
    const today = new Date();

    let low = 0;
    let expiring = 0;

    medicines.forEach(m => {
      // Low Stock
      if (m.stock <= LOW_STOCK_THRESHOLD && m.stock > 0) low++;

      // Expiring
      const expiryDate = new Date(m.expiryDate);
      const diffTime = expiryDate.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      if (diffDays <= EXPIRY_WARNING_DAYS && diffDays > 0) expiring++;
    });

    setLowStockCount(low);
    setExpiringCount(expiring);
  }, [activeTab]);

  const menuItems = [
    { id: Tab.COUNTER, label: 'Counter', icon: Store, allowed: true },
    { id: Tab.INVENTORY, label: 'Inventory', icon: Package, allowed: user.permissions.inventory },
    { id: Tab.STOCK, label: 'Stock', icon: Truck, allowed: user.permissions.stock },
    { id: Tab.SUPPLIERS, label: 'Suppliers', icon: Contact, allowed: user.permissions.suppliers },
    { id: Tab.REPORTS, label: 'Reports', icon: BarChart3, allowed: true },
    { id: Tab.SETTINGS, label: 'Settings', icon: Settings, allowed: user.permissions.settings },
  ];

  return (
    <aside className={clsx(
      "fixed z-40 bg-white/60 backdrop-blur-xl border-gray-200 shadow-xl transition-all duration-300",
      // Desktop & Tablet: Compact Icon Sidebar
      "lg:left-0 lg:top-0 lg:w-20 lg:h-screen lg:flex-col lg:border-r lg:justify-between lg:pb-0",
      "md:left-0 md:top-0 md:w-20 md:h-screen md:flex-col md:border-r md:border-t-0 md:justify-between",
      // Mobile: Bottom Navigation
      "bottom-0 left-0 w-full h-auto border-t flex flex-row items-center justify-between px-2 py-1 md:py-0"
    )}>
      {/* Brand Header - Hidden on Mobile, Icon Only on Desktop/Tablet */}
      <div className="hidden md:flex p-6 items-center gap-3 border-b border-gray-100/50 justify-center">
        <div className="w-10 h-10 bg-gradient-to-br from-medical-blue to-blue-400 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/20 text-white shrink-0">
          <Stethoscope size={20} />
        </div>
      </div>

      {/* Navigation Items */}
      <nav className={clsx(
        "flex-1 md:px-3 md:py-6 md:space-y-1.5",
        "flex flex-row md:flex-col w-full md:w-auto overflow-x-auto md:overflow-x-visible items-center md:items-stretch gap-1 md:gap-2 justify-evenly md:justify-start no-scrollbar"
      )}>
        {menuItems.map((item) => {
          if (!item.allowed) return null;
          const Icon = item.icon;
          const isActive = activeTab === item.id;

          return (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={clsx(
                "group relative flex items-center transition-all duration-300 rounded-2xl shrink-0",
                // Desktop/Tablet: Centered Icons
                "lg:justify-center lg:px-2 lg:py-3",
                "md:justify-center md:px-2 md:py-3",
                // Mobile
                "flex-col gap-1 p-2 min-w-[60px]",
                isActive 
                  ? "bg-gray-900 text-white shadow-lg shadow-gray-900/20" 
                  : "text-gray-500 hover:bg-white hover:text-gray-900 hover:shadow-sm"
              )}
              title={item.label}
            >
              <Icon size={20} className={isActive ? "text-white" : "text-gray-400 group-hover:text-gray-900"} />
              <span className={clsx(
                "font-semibold transition-all duration-300",
                // Desktop/Tablet: Hidden
                "lg:hidden",
                "md:hidden",
                // Mobile: Visible, Tiny
                "block text-[9px]"
              )}>
                {item.label}
              </span>

              {/* Badge for Stock Tab if Alerts exist */}
              {item.id === Tab.STOCK && (lowStockCount > 0 || expiringCount > 0) && !isActive && (
                <span className="absolute top-2 right-2 md:top-1 md:right-1 lg:top-1 lg:right-1 w-2 h-2 bg-red-500 rounded-full animate-pulse border border-white"></span>
              )}
            </button>
          );
        })}
      </nav>

      {/* Footer / User Info - Icon Only on Desktop/Tablet */}
      <div className="hidden md:block p-4 border-t border-gray-100/50">
        <button 
          onClick={onLogout}
          className={clsx(
            "w-full flex items-center justify-center gap-2 text-gray-500 hover:text-red-600 rounded-xl hover:bg-red-50 transition-colors font-bold uppercase tracking-widest",
            "lg:p-3 lg:text-[0px]", // Icon only
            "md:p-3 md:text-[0px]"  // Icon only
          )}
          title={`Sign Out (${user.username})`}
        >
          <LogOut size={18} />
        </button>
      </div>
    </aside>
  );
};

import React, { useState } from 'react';
import { X, Divide, X as Multiply, Minus, Plus, Equal, Delete } from 'lucide-react';

interface CalculatorProps {
  onClose: () => void;
}

export const Calculator: React.FC<CalculatorProps> = ({ onClose }) => {
  const [display, setDisplay] = useState('0');
  const [equation, setEquation] = useState('');

  const handleNumber = (num: string) => {
    setDisplay(display === '0' ? num : display + num);
  };

  const handleOperator = (op: string) => {
    setEquation(display + ' ' + op + ' ');
    setDisplay('0');
  };

  const calculate = () => {
    try {
      // eslint-disable-next-line no-eval
      const result = eval((equation + display).replace('x', '*'));
      setDisplay(String(result));
      setEquation('');
    } catch (e) {
      setDisplay('Error');
    }
  };

  const clear = () => {
    setDisplay('0');
    setEquation('');
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
      <div className="bg-gray-900 p-6 rounded-3xl shadow-2xl w-full max-w-xs animate-in zoom-in duration-200 border border-gray-700">
        <div className="flex justify-between items-center mb-4">
          <span className="text-white font-bold text-sm">Calculator</span>
          <button onClick={onClose} className="text-gray-400 hover:text-white"><X size={18} /></button>
        </div>

        <div className="bg-gray-800 rounded-xl p-4 mb-4 text-right h-24 flex flex-col justify-end">
          <div className="text-gray-400 text-xs h-4">{equation}</div>
          <div className="text-white text-3xl font-mono overflow-hidden">{display}</div>
        </div>

        <div className="grid grid-cols-4 gap-3">
          <button onClick={clear} className="col-span-3 bg-gray-700 hover:bg-gray-600 text-red-400 p-4 rounded-xl font-bold">AC</button>
          <button onClick={() => handleOperator('/')} className="bg-orange-500 hover:bg-orange-600 text-white p-4 rounded-xl flex items-center justify-center"><Divide size={20} /></button>

          {['7','8','9'].map(n => <button key={n} onClick={() => handleNumber(n)} className="bg-gray-800 hover:bg-gray-700 text-white p-4 rounded-xl font-bold">{n}</button>)}
          <button onClick={() => handleOperator('*')} className="bg-orange-500 hover:bg-orange-600 text-white p-4 rounded-xl flex items-center justify-center"><Multiply size={20} /></button>

          {['4','5','6'].map(n => <button key={n} onClick={() => handleNumber(n)} className="bg-gray-800 hover:bg-gray-700 text-white p-4 rounded-xl font-bold">{n}</button>)}
          <button onClick={() => handleOperator('-')} className="bg-orange-500 hover:bg-orange-600 text-white p-4 rounded-xl flex items-center justify-center"><Minus size={20} /></button>

          {['1','2','3'].map(n => <button key={n} onClick={() => handleNumber(n)} className="bg-gray-800 hover:bg-gray-700 text-white p-4 rounded-xl font-bold">{n}</button>)}
          <button onClick={() => handleOperator('+')} className="bg-orange-500 hover:bg-orange-600 text-white p-4 rounded-xl flex items-center justify-center"><Plus size={20} /></button>

          <button onClick={() => handleNumber('0')} className="col-span-2 bg-gray-800 hover:bg-gray-700 text-white p-4 rounded-xl font-bold">0</button>
          <button onClick={() => handleNumber('.')} className="bg-gray-800 hover:bg-gray-700 text-white p-4 rounded-xl font-bold">.</button>
          <button onClick={calculate} className="bg-orange-500 hover:bg-orange-600 text-white p-4 rounded-xl flex items-center justify-center"><Equal size={20} /></button>
        </div>
      </div>
    </div>
  );
};

