               <Stethoscope size={16} />
            </div>
            <span className="font-extrabold text-gray-800 tracking-tight">Pharma-Core</span>
         </div>
         <div className="flex items-center gap-2">
            <div className="text-right hidden sm:block">
               <p className="text-[10px] font-bold text-gray-500 uppercase tracking-wider">{user.role}</p>
               <p className="text-xs font-bold text-gray-800 leading-none capitalize">{user.username}</p>
            </div>
            <button 
               onClick={() => setUser(null)}
               className="p-2 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition-colors"
               aria-label="Logout"
            >
               <LogOut size={18} />
            </button>
         </div>
      </header>

      <Sidebar 
