import React, { useState, useEffect } from 'react';
import { Plus, Search, Edit, Trash, Truck, ArrowUpRight, ArrowDownLeft, Calendar } from 'lucide-react';
import { Medicine, StockEntry, User } from '../types';
import { storageService } from '../services/storageService';
import { Button } from '../components/ui/Button';
import { MedicineCard } from '../components/MedicineCard';
import { MedicineFormModal } from '../components/MedicineFormModal';
import { clsx } from 'clsx';

interface InventoryProps {
  user: User;
}

const Inventory: React.FC<InventoryProps> = ({ user }) => {
  const [activeSubTab, setActiveSubTab] = useState<'products' | 'stock'>('products');

  // --- INVENTORY / PRODUCTS STATE ---
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [search, setSearch] = useState('');
  const [isFormModalOpen, setFormModalOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);

  // --- STOCK STATE ---
  const [stockEntries, setStockEntries] = useState<StockEntry[]>([]);
  const [selectedMedId, setSelectedMedId] = useState('');
  const [quantity, setQuantity] = useState(0);
  const [type, setType] = useState<'IN' | 'OUT'>('IN');
  const [reason, setReason] = useState('New Batch');
  const [batch, setBatch] = useState('');

  // Initial Load & Permissions Check
  useEffect(() => {
    refreshData();
    // Default to available tab if permission for current is missing
    if (!user.permissions.inventory && user.permissions.stock) {
      setActiveSubTab('stock');
    }
  }, [user]);

  const refreshData = () => {
    setMedicines(storageService.getMedicines());
    setStockEntries(storageService.getStockEntries().reverse());
  };

  // --- PRODUCT LOGIC ---
  const filteredMedicines = medicines.filter(m => {
    const matchesSearch = 
      m.name.toLowerCase().includes(search.toLowerCase()) ||
      m.genericName.toLowerCase().includes(search.toLowerCase());

    // Hide Expired Items from list view (optional filter, keeping same as before)
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(m.expiryDate);
    const isNotExpired = expiry >= today;

    return matchesSearch && isNotExpired;
  });

  const handleAddNewProduct = () => {
    setEditingMedicine(null);
    setFormModalOpen(true);
  };

  const handleEditProduct = (med: Medicine) => {
    setEditingMedicine(med);
    setFormModalOpen(true);
  };

  const handleDeleteProduct = (id: string) => {
    if(confirm("Are you sure you want to delete this medicine?")) {
      const updated = medicines.filter(m => m.id !== id);
      storageService.saveMedicines(updated);
      refreshData();
    }
  };

  const handleSaveProduct = (med: Medicine) => {
    let updatedList;
    if (editingMedicine) {
      updatedList = medicines.map(m => m.id === med.id ? med : m);
    } else {
      updatedList = [med, ...medicines];
    }
    storageService.saveMedicines(updatedList);
    refreshData();
  };

  // --- STOCK LOGIC ---
  const handleStockSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedMedId || quantity <= 0) return;

    const med = medicines.find(m => m.id === selectedMedId);
    if (!med) return;

    const entry: StockEntry = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      medicineId: med.id,
      medicineName: med.name,
      quantity,
      type,
      reason,
      batchNumber: type === 'IN' ? batch : undefined
    };

    storageService.addStockEntry(entry);
    refreshData();

    // Reset Form
    setQuantity(0);
    setBatch('');
  };

  return (
    <div className="h-full flex flex-col">
      {/* Tab Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Inventory & Stock</h2>
          <p className="text-gray-500 text-sm">Manage products and stock movements.</p>
        </div>

        <div className="flex bg-gray-200/50 p-1 rounded-xl">
           {user.permissions.inventory && (
             <button 
               onClick={() => setActiveSubTab('products')}
               className={clsx(
                 "px-6 py-2 rounded-lg text-sm font-bold transition-all",
                 activeSubTab === 'products' ? "bg-white text-gray-900 shadow-sm" : "text-gray-500 hover:text-gray-700"
               )}
             >
               Product List
             </button>
           )}
           {user.permissions.stock && (
             <button 
               onClick={() => setActiveSubTab('stock')}
               className={clsx(
                 "px-6 py-2 rounded-lg text-sm font-bold transition-all",
                 activeSubTab === 'stock' ? "bg-white text-gray-900 shadow-sm" : "text-gray-500 hover:text-gray-700"
               )}
             >
               Stock Management
             </button>
           )}
        </div>
      </div>

      {/* --- PRODUCTS VIEW --- */}
      {activeSubTab === 'products' && user.permissions.inventory && (
        <>
          <div className="flex items-center gap-3 mb-4">
            <div className="relative flex-1 md:max-w-md">
               <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
               <input 
                 type="text" 
                 placeholder="Search inventory..." 
                 className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none shadow-sm"
                 value={search}
                 onChange={(e) => setSearch(e.target.value)}
               />
            </div>
            <Button onClick={handleAddNewProduct} className="gap-2 shadow-lg shadow-blue-500/30 whitespace-nowrap ml-auto">
              <Plus size={18} /> New SKU
            </Button>
          </div>

          <div className="flex-1 overflow-y-auto pr-2 pb-20">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4 gap-4">
               {filteredMedicines.length === 0 && (
                 <div className="col-span-full py-20 text-center text-gray-400">
                   No medicines found matching your search (Expired items hidden).
                 </div>
               )}
               {filteredMedicines.map(med => (
                 <MedicineCard 
                   key={med.id} 
                   medicine={med} 
                   actionSlot={
                     <>
                       <button 
                         onClick={(e) => { e.stopPropagation(); handleEditProduct(med); }} 
                         className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-blue-50 text-medical-blue hover:bg-blue-100 text-[10px] font-bold transition-colors"
                       >
                         <Edit size={12} /> Edit
                       </button>
                       <button 
                         onClick={(e) => { e.stopPropagation(); handleDeleteProduct(med.id); }} 
                         className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-red-50 text-red-500 hover:bg-red-100 text-[10px] font-bold transition-colors"
                       >
                         <Trash size={12} /> Del
                       </button>
                     </>
                   }
                 />
               ))}
            </div>
          </div>

          <MedicineFormModal 
            isOpen={isFormModalOpen}
            onClose={() => setFormModalOpen(false)}
            onSave={handleSaveProduct}
            initialData={editingMedicine}
          />
        </>
      )}

      {/* --- STOCK VIEW --- */}
      {activeSubTab === 'stock' && user.permissions.stock && (
        <div className="h-full flex flex-col lg:flex-row gap-6 overflow-hidden">
           {/* Left: Entry Form */}
           <div className="w-full lg:w-80 flex flex-col gap-4 shrink-0 overflow-y-auto pb-4">
             <div className="glass-panel p-6 rounded-xl border border-gray-200">
               <div className="flex items-center gap-2 mb-4 text-medical-blue">
                 <Truck size={24} />
                 <h2 className="text-lg font-bold">Stock Entry</h2>
               </div>

               <form onSubmit={handleStockSubmit} className="space-y-4">
                 <div>
                   <label className="text-xs font-semibold text-gray-500 uppercase">Action Type</label>
                   <div className="flex gap-2 mt-1">
                     <button type="button" onClick={() => { setType('IN'); setReason('New Batch'); }} className={clsx("flex-1 py-2 rounded-lg text-sm font-medium border transition-colors", type === 'IN' ? "bg-green-50 border-green-200 text-green-700" : "bg-gray-50 border-gray-200 text-gray-500")}>Stock In</button>
                     <button type="button" onClick={() => { setType('OUT'); setReason('Expired'); }} className={clsx("flex-1 py-2 rounded-lg text-sm font-medium border transition-colors", type === 'OUT' ? "bg-red-50 border-red-200 text-red-700" : "bg-gray-50 border-gray-200 text-gray-500")}>Stock Out</button>
                   </div>
                 </div>

                 <div>
                   <label className="text-xs font-semibold text-gray-500 uppercase">Select Medicine</label>
                   <select 
                     className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                     value={selectedMedId}
                     onChange={(e) => setSelectedMedId(e.target.value)}
                     required
                   >
                     <option value="">-- Select SKU --</option>
                     {medicines.map(m => (
                       <option key={m.id} value={m.id}>{m.name} ({m.stock} {m.unit})</option>
                     ))}
                   </select>
                 </div>

                 <div>
                   <label className="text-xs font-semibold text-gray-500 uppercase">Quantity</label>
                   <input 
                     type="number" 
                     min="1"
                     className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                     value={quantity || ''}
                     onChange={(e) => setQuantity(parseInt(e.target.value))}
                     required
                   />
                 </div>

                 {type === 'IN' ? (
                    <div>
                       <label className="text-xs font-semibold text-gray-500 uppercase">Batch Number</label>
                       <input 
                         type="text" 
                         className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                         value={batch}
                         onChange={(e) => setBatch(e.target.value)}
                         placeholder="e.g. B-202X"
                       />
                    </div>
                 ) : (
                    <div>
                       <label className="text-xs font-semibold text-gray-500 uppercase">Reason</label>
                       <select 
                         className="w-full mt-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:ring-2 focus:ring-medical-blue outline-none"
                         value={reason}
                         onChange={(e) => setReason(e.target.value)}
                       >
                         <option value="Expired">Expired</option>
                         <option value="Damaged">Damaged</option>
                         <option value="Lost">Lost/Stolen</option>
                       </select>
                    </div>
                 )}

                 <Button type="submit" className="w-full mt-2" variant={type === 'IN' ? 'primary' : 'danger'}>
                   {type === 'IN' ? 'Add Stock' : 'Remove Stock'}
                 </Button>
               </form>
             </div>
           </div>

           {/* Right: History Log */}
           <div className="flex-1 glass-panel rounded-xl border border-gray-200 overflow-hidden flex flex-col min-h-[400px]">
             <div className="p-4 border-b border-gray-100 bg-gray-50/50">
               <h3 className="font-semibold text-gray-700">Recent Movements</h3>
             </div>
             <div className="overflow-auto flex-1 pb-10">
               <table className="w-full text-left min-w-[600px]">
                 <thead className="bg-white sticky top-0">
                   <tr className="text-xs font-bold text-gray-400 uppercase border-b border-gray-100">
                     <th className="p-4">Date</th>
                     <th className="p-4">Type</th>
                     <th className="p-4">Medicine</th>
                     <th className="p-4 text-center">Qty</th>
                     <th className="p-4">Reason / Batch</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-gray-50">
                   {stockEntries.length === 0 && (
                     <tr><td colSpan={5} className="p-8 text-center text-gray-400">No stock history available</td></tr>
                   )}
                   {stockEntries.map(entry => (
                     <tr key={entry.id} className="hover:bg-blue-50/20">
                       <td className="p-4 text-sm text-gray-500 flex items-center gap-2">
                         <Calendar size={14} />
                         {new Date(entry.date).toLocaleDateString()}
                       </td>
                       <td className="p-4">
                         <span className={clsx("inline-flex items-center gap-1 px-2 py-1 rounded-md text-xs font-bold", 
                           entry.type === 'IN' ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"
                         )}>
                           {entry.type === 'IN' ? <ArrowDownLeft size={12}/> : <ArrowUpRight size={12}/>}
                           {entry.type}
                         </span>
                       </td>
                       <td className="p-4 font-medium text-gray-800">{entry.medicineName}</td>
                       <td className="p-4 text-center font-bold text-gray-600">{entry.quantity}</td>
                       <td className="p-4 text-sm text-gray-500">
                         {entry.type === 'IN' ? (
                           <span className="font-mono bg-gray-100 px-2 py-0.5 rounded text-xs text-gray-600">{entry.batchNumber || 'N/A'}</span>
                         ) : (
                           entry.reason
                         )}
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

export interface Medicine {
  id: string;
  name: string;
  genericName: string; // Salt
  category: string;
  price: number;
  stock: number;
  expiryDate: string;
  batchNumber: string;
  unit: 'Tablet' | 'Strip' | 'Bottle' | 'Box' | 'Injection' | 'Inhaler' | 'Tube';
}

export interface CartItem extends Medicine {
  quantity: number;
  saleUnit: string;     // The unit being sold (e.g. 'Box')
  salePrice: number;    // The price of the unit being sold
  skuDeduction: number; // Stock deduction factor (e.g. 10 if selling Box when SKU is Strip)
}

export interface Sale {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  staffName: string;
  paymentMethod: 'Cash' | 'Card' | 'UPI';
  customerName?: string;
  customerPhone?: string;
}

export interface StockEntry {
  id: string;
  date: string;
  medicineId: string;
  medicineName: string;
  quantity: number;
  type: 'IN' | 'OUT';
  reason: string; // e.g., 'New Batch', 'Expired', 'Damaged'
  batchNumber?: string;
  supplier?: string;
}

export interface Patient {
  id: string;
  name: string;
  phone: string;
  age?: number;
  gender?: 'Male' | 'Female' | 'Other';
  chronicConditions?: string;
  history: string[]; // Array of sale IDs
}

export interface Supplier {
  id: string;
  name: string;
  contact: string;
  email?: string;
  medicinesSupplied: string[];
}

export interface User {
  username: string;
  role: 'admin' | 'staff';
  permissions: {
    inventory: boolean;
    stock: boolean;
    suppliers: boolean;
    settings: boolean;
  };
}

export interface CompanySettings {
  name: string;
  license: string;
  address: string;
  contact: string;
}

export enum Tab {
  COUNTER = 'COUNTER',
  INVENTORY = 'INVENTORY',
  SUPPLIERS = 'SUPPLIERS',
  REPORTS = 'REPORTS',
  SETTINGS = 'SETTINGS'
}

import { INITIAL_MEDICINES } from '../constants';
import { Medicine, Sale, StockEntry, Patient, Supplier, CompanySettings } from '../types';

const MEDICINES_KEY = 'pharma_core_medicines';
const SALES_KEY = 'pharma_core_sales';
const STOCK_KEY = 'pharma_core_stock';
const PATIENTS_KEY = 'pharma_core_patients';
const SUPPLIERS_KEY = 'pharma_core_suppliers';
const COMPANY_KEY = 'pharma_core_company';

class StorageService {
  // --- Company Settings ---
  getCompanySettings(): CompanySettings {
    const stored = localStorage.getItem(COMPANY_KEY);
    return stored ? JSON.parse(stored) : { 
      name: 'Pharma-Core', 
      license: '', 
      address: '123 Health Ave, Med City', 
      contact: '+92 300 1234567' 
    };
  }

  saveCompanySettings(settings: CompanySettings) {
    localStorage.setItem(COMPANY_KEY, JSON.stringify(settings));
  }

  // --- Medicines ---
  getMedicines(): Medicine[] {
    const stored = localStorage.getItem(MEDICINES_KEY);
    if (!stored) {
      // @ts-ignore - casting readonly to mutable for initial setup
      const initial: Medicine[] = [...INITIAL_MEDICINES];
      localStorage.setItem(MEDICINES_KEY, JSON.stringify(initial));
      return initial;
    }
    return JSON.parse(stored);
  }

  saveMedicines(medicines: Medicine[]) {
    localStorage.setItem(MEDICINES_KEY, JSON.stringify(medicines));
  }

  // --- Sales ---
  getSales(): Sale[] {
    const stored = localStorage.getItem(SALES_KEY);
    return stored ? JSON.parse(stored) : [];
  }

  addSale(sale: Sale) {
    // 1. Save the Sale Record
    const sales = this.getSales();
    sales.push(sale);
    localStorage.setItem(SALES_KEY, JSON.stringify(sales));

    // 2. Update Inventory & 3. Create Stock Logs (Interconnection)
    const medicines = this.getMedicines();
    const stockEntries = this.getStockEntries();
    const timestamp = new Date().toISOString();

    sale.items.forEach(item => {
      const medIndex = medicines.findIndex(m => m.id === item.id);

      if (medIndex >= 0) {
        // Calculate total quantity in base units (e.g., if Box, deduct 10 strips)
        const deductionAmount = item.quantity * item.skuDeduction;

        // Update Stock
        medicines[medIndex].stock = Math.max(0, medicines[medIndex].stock - deductionAmount);

        // Create Automated Stock Entry for Audit
        const entry: StockEntry = {
          id: `sys-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
          date: timestamp,
          medicineId: item.id,
          medicineName: item.name,
          quantity: deductionAmount, // Log the base unit amount
          type: 'OUT',
          reason: `Sale #${sale.id.substr(-6)}`, // Link to Invoice ID
          batchNumber: medicines[medIndex].batchNumber
        };
        stockEntries.push(entry);
      }
    });

    this.saveMedicines(medicines);
    localStorage.setItem(STOCK_KEY, JSON.stringify(stockEntries));
  }

  // --- Stock Entries ---
  getStockEntries(): StockEntry[] {
    const stored = localStorage.getItem(STOCK_KEY);
    return stored ? JSON.parse(stored) : [];
  }

  addStockEntry(entry: StockEntry) {
    const entries = this.getStockEntries();
    entries.push(entry);
    localStorage.setItem(STOCK_KEY, JSON.stringify(entries));

    // Update Medicine Stock
    const medicines = this.getMedicines();
    const medIndex = medicines.findIndex(m => m.id === entry.medicineId);
    if (medIndex >= 0) {
      if (entry.type === 'IN') {
        medicines[medIndex].stock += entry.quantity;
      } else {
        medicines[medIndex].stock = Math.max(0, medicines[medIndex].stock - entry.quantity);
      }
      // Update batch if provided on input
      if (entry.batchNumber && entry.type === 'IN') {
        medicines[medIndex].batchNumber = entry.batchNumber;
      }
      this.saveMedicines(medicines);
    }
  }

  // --- Patients ---
  getPatients(): Patient[] {
    const stored = localStorage.getItem(PATIENTS_KEY);
    return stored ? JSON.parse(stored) : [];
  }

  addPatient(patient: Patient) {
    const patients = this.getPatients();
    patients.push(patient);
    localStorage.setItem(PATIENTS_KEY, JSON.stringify(patients));
  }

  // --- Suppliers ---
  getSuppliers(): Supplier[] {
    const stored = localStorage.getItem(SUPPLIERS_KEY);
    return stored ? JSON.parse(stored) : [];
  }

  addSupplier(supplier: Supplier) {
    const suppliers = this.getSuppliers();
    suppliers.push(supplier);
    localStorage.setItem(SUPPLIERS_KEY, JSON.stringify(suppliers));
  }

  // --- Data Management (Backup/Restore) ---

  exportData(): string {
    const data = {
      medicines: this.getMedicines(),
      sales: this.getSales(),
      stockEntries: this.getStockEntries(),
      patients: this.getPatients(),
      suppliers: this.getSuppliers(),
      company: this.getCompanySettings(),
      timestamp: new Date().toISOString(),
      appVersion: '2.0.0'
    };
    return JSON.stringify(data, null, 2);
  }

  async importData(jsonString: string): Promise<{success: boolean, message: string}> {
    try {
      const data = JSON.parse(jsonString);

      // Basic validation
      if (!data.timestamp) return { success: false, message: "Invalid backup file format." };

      if (data.medicines) this.saveMedicines(data.medicines);
      if (data.sales) localStorage.setItem(SALES_KEY, JSON.stringify(data.sales));
      if (data.stockEntries) localStorage.setItem(STOCK_KEY, JSON.stringify(data.stockEntries));
      if (data.patients) localStorage.setItem(PATIENTS_KEY, JSON.stringify(data.patients));
      if (data.suppliers) localStorage.setItem(SUPPLIERS_KEY, JSON.stringify(data.suppliers));
      if (data.company) this.saveCompanySettings(data.company);

      return { success: true, message: "Data restored successfully." };
    } catch (e) {
      console.error(e);
      return { success: false, message: "Error parsing backup file." };
    }
  }

  // --- System ---
  resetData() {
    localStorage.removeItem(MEDICINES_KEY);
    localStorage.removeItem(SALES_KEY);
    localStorage.removeItem(STOCK_KEY);
    localStorage.removeItem(PATIENTS_KEY);
    localStorage.removeItem(SUPPLIERS_KEY);
    localStorage.removeItem(COMPANY_KEY);
    window.location.reload();
  }
}

