const Settings: React.FC = () => {
  const [company, setCompany] = useState<CompanySettings>({
    name: '',
    license: '',
    address: '',
    contact: ''
  });
  const [saveStatus, setSaveStatus] = useState('');

  useEffect(() => {
    setCompany(storageService.getCompanySettings());
  }, []);

  const handleSaveCompany = (e: React.FormEvent) => {
    e.preventDefault();
    storageService.saveCompanySettings(company);
    setSaveStatus('Settings Saved!');
    setTimeout(() => setSaveStatus(''), 2000);
    // Reload to reflect header changes immediately would require app state lift, 
    // but the Sidebar/App effect handles it on tab switch usually.
    // For immediate effect we can force update or just let user navigate.
  };

  const handleBackup = (format: 'json' | 'csv_inv' | 'csv_sales') => {
    let dataStr = '';
    let filename = '';
    let mime = '';

    const timestamp = new Date().toISOString().slice(0,10);

    if (format === 'json') {
      dataStr = storageService.exportData();
      filename = `pharma_core_backup_${timestamp}.json`;
      mime = 'application/json';
    } else if (format === 'csv_inv') {
      // Generate Inventory CSV
      const meds = storageService.getMedicines();
      const headers = ['ID', 'Name', 'Generic', 'Category', 'Stock', 'Unit', 'Price', 'Expiry', 'Batch'];
      const rows = meds.map(m => [m.id, m.name, m.genericName, m.category, m.stock, m.unit, m.price, m.expiryDate, m.batchNumber]);
      dataStr = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
      filename = `inventory_${timestamp}.csv`;
      mime = 'text/csv';
    } else if (format === 'csv_sales') {
      // Generate Sales CSV
      const sales = storageService.getSales();
      const headers = ['InvoiceID', 'Date', 'Total', 'Payment', 'Staff', 'Customer'];
      const rows = sales.map(s => [s.id, s.date, s.total, s.paymentMethod, s.staffName, s.customerName || '']);
      dataStr = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
      filename = `sales_${timestamp}.csv`;
      mime = 'text/csv';
    }

    const blob = new Blob([dataStr], { type: mime });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const json = event.target?.result as string;
      if (confirm("WARNING: This will overwrite current data with the backup file. Continue?")) {
        const result = await storageService.importData(json);
        alert(result.message);
        if (result.success) window.location.reload();
      }
    };
    reader.readAsText(file);
    // Reset input
    e.target.value = '';
  };

  return (
