                    <span className="flex items-center gap-2"><FileSpreadsheet size={18} className="text-green-600"/> Inventory List (.csv)</span>
                    <Download size={16} className="text-gray-400 group-hover:text-gray-600" />
                 </Button>
                 <Button variant="secondary" onClick={() => handleBackup('csv_sales')} className="w-full justify-between group">
                    <span className="flex items-center gap-2"><FileSpreadsheet size={18} className="text-green-600"/> Sales History (.csv)</span>
                    <Download size={16} className="text-gray-400 group-hover:text-gray-600" />
                 </Button>
               </div>
               <p className="text-[10px] text-gray-400">
                 * .json files are for full system restore. .csv files are for Excel/Sheets viewing.
               </p>
             </div>

             {/* Import */}
             <div className="space-y-4">
               <h4 className="font-bold text-gray-700 text-sm uppercase">Restore / Upload</h4>
               <div className="border-2 border-dashed border-gray-200 rounded-xl p-6 flex flex-col items-center justify-center text-center hover:bg-gray-50 transition-colors relative">
                 <Upload size={32} className="text-gray-300 mb-2" />
                 <p className="text-sm font-medium text-gray-600">Click to Restore System</p>
                 <p className="text-xs text-gray-400 mt-1">Accepts .json backup files only</p>
                 <input 
                   type="file" 
                   accept=".json" // Limiting upload to JSON to prevent errors with random excel files
                   onChange={handleRestore}
                   className="absolute inset-0 opacity-0 cursor-pointer"
