               <div className="p-3 bg-yellow-50 rounded-lg border border-yellow-100">
                 <p className="text-[10px] text-yellow-800 font-medium">
                   <span className="font-bold">Note:</span> Restoring will completely replace all current medicines, sales, and settings with the data from the file.
                 </p>
               </div>
             </div>
          </div>
        </section>

        {/* 3. Developer Info & Danger Zone */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
