import { storageService } from './services/storageService';

const App: React.FC = () => {
  // Initialize with Admin user to make Login window inactive (bypass it)
  const [user, setUser] = useState<User | null>({
    username: 'admin',
    role: 'admin',
    permissions: { 
      inventory: true, 
      stock: true, 
      suppliers: true, 
      settings: true 
    }
  });

  const [activeTab, setActiveTab] = useState<Tab>(Tab.COUNTER);
  const [showCalculator, setShowCalculator] = useState(false);
  const [showStickyNote, setShowStickyNote] = useState(false);
  const [companyName, setCompanyName] = useState('Pharma-Core');

  // Offline Mode State
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Load Company Name
    const settings = storageService.getCompanySettings();
    if (settings.name) setCompanyName(settings.name);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, [activeTab]); // Reload when tab changes in case settings were updated

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case Tab.COUNTER:
        return <Counter />;
      case Tab.INVENTORY:
        return <Inventory user={user} />;
      case Tab.SUPPLIERS:
        return <Suppliers />;
      case Tab.REPORTS:
        return <Reports />;
      case Tab.SETTINGS:
        return <Settings />;
      default:
        return <Counter />;
    }
  };

  return (
    <div className="flex flex-col md:flex-row h-screen bg-[#F0F2F5] text-gray-900 font-sans overflow-hidden">

      {/* Mobile Top Header (Visible only on Mobile) */}
      <header className="md:hidden flex items-center justify-between p-4 bg-medical-blue text-white shadow-md fixed top-0 left-0 w-full z-30 h-16">
         <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-white/20 backdrop-blur-sm rounded-lg flex items-center justify-center text-white shadow-sm">
               <Stethoscope size={16} />
            </div>
            <span className="font-extrabold tracking-tight text-lg">{companyName}</span>
         </div>
         <div className="flex items-center gap-2">
            {/* Mobile Calculator */}
            <button 
              onClick={() => setShowCalculator(true)}
              className="p-2 bg-white/10 hover:bg-white/20 rounded-lg text-white transition-colors"
            >
              <CalculatorIcon size={18} />
            </button>

            {/* Mobile Sticky Note */}
            <button 
              onClick={() => setShowStickyNote(true)}
              className="p-2 bg-white/10 hover:bg-white/20 rounded-lg text-white transition-colors relative"
            >
               <div className="absolute top-2 right-2 w-1.5 h-1.5 bg-yellow-400 rounded-full"></div>
               <StickyNoteIcon size={18} />
            </button>

            <div className="text-right hidden sm:block">
               <p className="text-[10px] font-bold text-blue-100 uppercase tracking-wider">{user.role}</p>
               <p className="text-xs font-bold text-white leading-none capitalize">{user.username}</p>
            </div>
            <button 
               onClick={() => setUser(null)}
               className="p-2 bg-red-500/20 text-white rounded-lg hover:bg-red-500/30 transition-colors"
               aria-label="Logout"
            >
               <LogOut size={18} />
            </button>
         </div>
      </header>

      <Sidebar 
        activeTab={activeTab} 
        onTabChange={setActiveTab} 
        user={user} 
        onLogout={() => setUser(null)} 
      />

      {/* Main Content Area */}
      {/* 
          Margins: 
          - ml-0 on mobile (Sidebar is bottom nav)
          - md:ml-20 on tablet/desktop (Sidebar is compact rail)

          Padding:
          - pt-20 on mobile (Clear Top Header)
          - pb-24 on mobile (Clear Bottom Nav)
          - md:p-6 normal padding on tablet/desktop
      */}
      <main className="flex-1 md:ml-20 lg:ml-20 p-4 pt-20 pb-24 md:p-6 md:pb-6 h-full overflow-hidden relative flex flex-col transition-all duration-300">

        {/* Desktop Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4 animate-in slide-in-from-top-4 duration-500">
          <div>
            <h1 className="text-3xl font-black text-gray-800 tracking-tight leading-none">{companyName}</h1>
            <p className="text-sm font-medium text-gray-500 mt-1 flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              {new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
          </div>
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowCalculator(true)}
              className="p-3 bg-white border border-gray-200 rounded-xl text-gray-600 hover:text-blue-600 hover:border-blue-200 hover:shadow-lg hover:-translate-y-1 transition-all group"
              title="Calculator"
            >
              <CalculatorIcon size={20} />
            </button>
            <button 
              onClick={() => setShowStickyNote(true)}
              className="p-3 bg-white border border-gray-200 rounded-xl text-gray-600 hover:text-yellow-600 hover:border-yellow-200 hover:shadow-lg hover:-translate-y-1 transition-all group relative"
              title="Sticky Notes"
            >
               <div className="absolute top-2 right-2 w-1.5 h-1.5 bg-yellow-400 rounded-full"></div>
               <StickyNoteIcon size={20} />
            </button>
          </div>
        </div>

        {/* Offline Banner */}
        {!isOnline && (
          <div className="mb-4 bg-gray-800 text-white px-4 py-2 rounded-xl flex items-center justify-between shadow-lg animate-in slide-in-from-top-2">
            <div className="flex items-center gap-3">
              <div className="p-1.5 bg-gray-700 rounded-lg">
                <WifiOff size={16} className="text-red-400" />
              </div>
              <div className="flex flex-col">
                <span className="text-sm font-bold leading-none">Offline Mode Active</span>
                <span className="text-[10px] text-gray-400 font-medium leading-tight">Changes are saved locally and will sync when online.</span>
              </div>
            </div>
            <div className="px-2 py-1 bg-gray-700 rounded text-[10px] font-bold uppercase tracking-wider text-gray-300">
              Local DB Active
            </div>
          </div>
        )}

        {renderContent()}

        {/* Modals */}
        {showCalculator && <Calculator onClose={() => setShowCalculator(false)} />}
        {showStickyNote && <StickyNote onClose={() => setShowStickyNote(false)} />}
      </main>
    </div>
  );
};

export default App;

